INSERT INTO `lecons` (`id`, `categorie_id`, `titre`, `contenu`, `ordre`, `date_creation`) VALUES
(7, 1, 'LEÇON 1 : LA SAINTE BIBLE', '<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: center;\" align=\"center\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">LE&Ccedil;ON N&deg; 1&nbsp;: LA SAINTE BIBLE</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify; line-height: 150%;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Le mot &lsquo;<strong style=\"mso-bidi-font-weight: normal;\">Bible&rsquo;</strong> vient du terme grec qui signifie &laquo;&nbsp;collection de livres&nbsp;&raquo;. La Bible est donc une compilation de 66 livres divis&eacute;s en deux sections appel&eacute;es &lsquo;<strong style=\"mso-bidi-font-weight: normal;\">testaments&rsquo;</strong>. L&rsquo;Ancien Testament comprend 39 livres et le Nouveau Testament 27. Elle fut &eacute;crite par des hommes des diff&eacute;rentes professions telles que&nbsp;: bergers, p&ecirc;cheurs, faiseurs de tente, docteurs, hommes d&rsquo;Etat, rois, et hommes sages, etc. Ce livre est connu sous plusieurs noms&nbsp;: Le livre des livres, le livre merveilleux, la lettre divine, le saint livre, les saintes &eacute;critures, etc.</span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify; line-height: 150%;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">&nbsp;Le pape Jean XXIII a &eacute;crit : &lsquo;<em style=\"mso-bidi-font-style: normal;\">C&rsquo;est un acte impardonnable pour le chr&eacute;tien de ne pas se familiariser avec le saint livre</em>&rsquo; c\'est-&agrave;-dire la Bible. Paul VI d&eacute;clara durant son pontificat&nbsp;: &lsquo;Il est n&eacute;cessaire d&rsquo;&eacute;tudier la Bible. C&rsquo;est seulement en buvant de cette source que nous pouvons maintenir une foi vivante. Cher(e) ami(e), lisons s&eacute;rieusement la Bible.<span style=\"mso-spacerun: yes;\">&nbsp; </span></span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Il est &eacute;crit&nbsp;: &lsquo;<em style=\"mso-bidi-font-style: normal;\">Vous sondez les Ecritures, parce que vous pensez avoir en elles la vie &eacute;ternelle&nbsp;; et ce sont elles qui rendent t&eacute;moignage de moi</em>&rsquo;.</span><span lang=\"FR\" style=\"font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\"> </span><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Jean 5&nbsp;: 39.</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify; line-height: 150%;\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">R&eacute;v&eacute;lation des paroles de Dieu aux humains. </span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Dieu s&rsquo;est r&eacute;v&eacute;l&eacute; aux proph&egrave;tes par des songes et des visions. <strong style=\"mso-bidi-font-weight: normal;\">Nombres 12 :6</strong>: &laquo;&Eacute;coutez bien mes paroles! Lorsqu\'il y aura parmi vous un proph&egrave;te, c\'est dans une <span style=\"mso-bidi-font-weight: bold;\">vision<strong> </strong></span>que moi, l\'&Eacute;ternel, je me&nbsp;</span><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">r&eacute;v&eacute;lerai &agrave; lui, c\'est dans un <span style=\"mso-bidi-font-weight: bold;\">songe<strong> </strong></span>que je lui parlerai <strong style=\"mso-bidi-font-weight: normal;\">&raquo;.</strong></span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: center;\" align=\"center\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">L&rsquo;Esprit de Dieu parlait aux hommes choisi par Dieu</span></strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">.</span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\"><span style=\"mso-spacerun: yes;\">&nbsp;</span>En <strong>2 Samuel 23 :2 </strong>David dit : &laquo; L&rsquo;Esprit de l\'Eternel parle par moi, et sa parole est sur ma langue &raquo;. Ez&eacute;chiel dit aussi : &laquo; l&rsquo;Esprit entra en moi &raquo; (<strong>Ez&eacute;chiel 2 :2</strong>) ; &laquo; l&rsquo;Esprit du Seigneur tomba sur moi &raquo; (<strong>Ez&eacute;chiel 11:5</strong>), &laquo;l&rsquo;Esprit m&rsquo;enleva et me transporta&raquo; (<strong>Ez&eacute;chiel 11:24</strong>). Mich&eacute;e a lui aussi &eacute;crit : &laquo; Mais moi, je suis rempli de force, de l\'Esprit de l&rsquo;&Eacute;ternel &raquo; (<strong style=\"mso-bidi-font-weight: normal;\">Mich&eacute;e<span style=\"mso-bidi-font-weight: bold;\"> 3&nbsp;:8). </span></strong></span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">2 Timoth&eacute;e 3:16-17</span></strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">: &laquo;Toute Ecriture est <strong>inspir&eacute;e </strong>de Dieu, et utile pour enseigner, pour convaincre, pour corriger, pour instruire dans la justice, afin que l&rsquo;homme de Dieu soit accompli et propre &agrave; toute bonne &oelig;uvre.&raquo; <strong>2 Pierre 1:20-21</strong>: &laquo;aucune proph&eacute;tie de l\'Ecriture ne peut &ecirc;tre un objet d\'interpr&eacute;tation particuli&egrave;re, car ce n\'est pas par une volont&eacute; d\'homme qu\'une proph&eacute;tie a jamais &eacute;t&eacute; apport&eacute;e, mais c\'est <strong>pouss&eacute;s par le Saint-Esprit </strong>que des hommes ont parl&eacute; de la part de Dieu comme la parole des hommes, mais, ainsi qu\'elle l\'est v&eacute;ritablement, comme la <strong>parole de Dieu</strong>, qui agit en vous qui croyez.&raquo;</span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: 0.0001pt; line-height: 150%; text-align: center;\"><strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Utilit&eacute; de la Bible.</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Psaumes 119 :105</span></strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\"> : &laquo; Ta parole est une <strong>lampe </strong>&agrave; mes pieds, Et une <strong>lumi&egrave;re </strong>sur mon sentier. &raquo; </span><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">H&eacute;breux 4 :12 :</span></strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\"> &laquo; Car la parole de Dieu est vivante et efficace, plus tranchante qu\'une &eacute;p&eacute;e quelconque &agrave; deux tranchants, p&eacute;n&eacute;trante jusqu\'&agrave; partager &acirc;me et esprit, jointures et moelles ; elle juge les sentiments et les pens&eacute;es du c&oelig;ur.&raquo;&nbsp; </span><span style=\"font-family: \'Times New Roman\',\'serif\';\"><strong><span lang=\"FR\">Proverbes 30 :5-6</span></strong><span lang=\"FR\"> : &laquo; Toute parole de Dieu est &eacute;prouv&eacute;e. Il est un <strong>bouclier </strong>pour ceux qui cherchent en lui un refuge. N\'ajoute rien &agrave; ses paroles, de peur qu\'il ne te reprenne et que tu ne sois trouv&eacute; menteur. &raquo;<strong> 2 Timoth&eacute;e 3:16-17</strong>: &laquo;Toute Ecriture est inspir&eacute;e de Dieu, et utile pour <strong>enseigner</strong>, pour <strong>convaincre</strong>, pour <strong>corriger</strong>, pour <strong>instruire </strong>dans la justice, afin que l\'homme de Dieu soit <strong>accompli </strong>et propre &agrave; toute <strong>bonne &oelig;uvre</strong>.&raquo; J&eacute;sus dit aussi en <strong>Jean 5:39</strong>: &laquo;Vous sondez les &Eacute;critures, parce que vous pensez avoir en elles la <strong>vie &eacute;ternelle</strong>: ce sont elles qui rendent t&eacute;moignage de moi.&raquo; Et en <strong>Jean 17:17</strong>, il dit: &laquo;<strong>Sanctifie</strong>-les par ta v&eacute;rit&eacute;: ta parole est la v&eacute;rit&eacute;.&raquo; La Parole de Dieu nous sanctifie. <strong>Actes 17 :11 </strong>dit que les Juifs de B&eacute;r&eacute;e &laquo; avaient des sentiments plus nobles que ceux de Thessalonique ; ils re&ccedil;urent la parole avec beaucoup d\'empressement, et ils examinaient chaque jour les Ecritures, pour voir si ce qu\'on leur disait &eacute;tait exact.&raquo; <strong>Apocalypse 1:3 </strong>dit: &laquo;Heureux celui qui lit et ceux qui entendent les paroles de la proph&eacute;tie, et qui gardent les choses qui y sont &eacute;crites! Car le temps est proche.&raquo; Voudriez-vous vous d&eacute;cider, par la gr&acirc;ce de Dieu, de commencer &agrave; examiner les Ecritures comme les B&eacute;r&eacute;ens et garder les choses qui y sont &eacute;crites pour que vous soyez heureux ?</span></span></p>\r\n<p class=\"MsoNormal\"><span lang=\"FR\">&nbsp;</span></p>\r\n<p class=\"MsoNormal\"><span lang=\"FR\">&nbsp;</span></p>', 1, '2025-10-23 09:10:29'),
(8, 1, 'LEÇON N°2 : LA TRINITÉ', '<p class=\"MsoNormal\" style=\"text-align: center;\" align=\"center\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-size: 14.0pt; mso-bidi-font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">LE&Ccedil;ON N&deg; 2&nbsp;: LA TRINIT&Eacute;</span></strong></p>\r\n<p class=\"MsoListParagraphCxSpFirst\" style=\"margin-left: 0cm; mso-add-space: auto; text-align: justify; text-indent: 14.2pt;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Avant de retourner au ciel, J&eacute;sus a confi&eacute; la mission &agrave; ses disciples d&rsquo;aller dans le monde entier et de faire de toutes les nations des disciples, les baptisant au nom du P&egrave;re, du Fils et du Saint Esprit. Et Il ajouta&nbsp;: Enseignez-leur tout ce que je vous ai prescrit</span><span lang=\"FR\" style=\"font-size: 9.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">. <strong style=\"mso-bidi-font-weight: normal;\">Matthieu 28&nbsp;: 19-20.</strong></span></p>\r\n<p class=\"MsoListParagraphCxSpMiddle\" style=\"margin-left: 0cm; mso-add-space: auto; text-align: justify; text-indent: 14.2pt;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">&laquo;&nbsp;Il y a un seul Dieu&nbsp;: P&egrave;re, Fils et Saint Esprit, unit&eacute; de trois personnes co- &eacute;ternelles. Dieu est immortel, omnipr&eacute;sent, omniscient, souverain et toujours pr&eacute;sent. Il est infini et d&eacute;passe la compr&eacute;hension humaine&nbsp;; cependant, il peut &ecirc;tre connu gr&acirc;ce &agrave; la r&eacute;v&eacute;lation qu&rsquo;il donne de lui- m&ecirc;me. Il est toujours digne d&rsquo;&ecirc;tre invoqu&eacute;, ador&eacute; et servi par toute la cr&eacute;ation.&nbsp;&raquo; <em style=\"mso-bidi-font-style: normal;\">(27 v&eacute;rit&eacute;s bibliques fondamentales, Dammarie- Les-Lys&nbsp;: vie et sant&eacute;, 2016, p. 24</em>. Les trois personnes de la Trinit&eacute; sont infiniment impliqu&eacute;es dans la r&eacute;demption de l&rsquo;humanit&eacute;. </span></p>\r\n<p class=\"MsoListParagraphCxSpMiddle\" style=\"margin-left: 0cm; mso-add-space: auto; text-align: justify; text-indent: 14.2pt;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Bien qu&rsquo;elles travaillent &agrave; comit&eacute;, la conception du plan du salut est attribu&eacute;e au P&egrave;re, l&rsquo;accomplissement de ce plan est attribu&eacute; au Fils et le Saint Esprit communique ce salut de fa&ccedil;on individuelle aux croyants. Dans cette &eacute;tude nous d&eacute;couvrirons que la Bible parle de la Trinit&eacute; et de son effort uni pour sauver l&rsquo;humanit&eacute; d&eacute;chue.</span></p>\r\n<p class=\"MsoListParagraphCxSpMiddle\" style=\"margin-left: 0cm; mso-add-space: auto; text-align: center; text-indent: 14.2pt;\" align=\"center\"><strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\'; color: black;\">Les indices de la trinit&eacute; dans l&rsquo;ancien testament</span></strong></p>\r\n<p class=\"MsoListParagraphCxSpMiddle\" style=\"margin-left: -4.5pt; mso-add-space: auto; text-align: justify; text-indent: 4.5pt;\"><strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\'; color: black;\">1. L&rsquo;usage du pluriel en rapport avec les actions divines</span></strong></p>\r\n<p class=\"MsoListParagraphCxSpLast\" style=\"margin-left: -4.5pt; mso-add-space: auto; text-align: justify; text-indent: 4.5pt;\"><strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Gen&egrave;se 1:26 </span></strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">&laquo;Puis Dieu dit:<strong> Faisons </strong>l&rsquo;homme &agrave; <strong>notre </strong>image, selon <strong>notre </strong>ressemblance&raquo;; <strong>Gen&egrave;se 3:22</strong>: &laquo;L\'&Eacute;ternel Dieu dit: Voici, l&rsquo;homme est devenu comme l\'un de <strong>nous</strong>, pour la connaissance du bien et du mal&raquo;;</span></p>\r\n<p class=\"MsoNormal\"><span lang=\"FR\">&nbsp;</span></p>\r\n<p class=\"Default\" style=\"text-align: justify;\"><strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Gen&egrave;se 11 :6-7</span></strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\"> : &laquo; Et l\'&Eacute;ternel dit : Voici, ils forment un seul peuple et ont tous une m&ecirc;me langue, et c\'est l&agrave; ce qu\'ils ont entrepris ; maintenant rien ne les emp&ecirc;cherait de faire tout ce qu\'ils auraient projet&eacute;. <strong>Allons</strong> ! <strong>Descendons</strong>, et l&agrave; <strong>confondons </strong>leur langage, afin qu\'ils n\'entendent plus la langue, les uns des autres. &raquo; &laquo;&nbsp;</span><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: FR;\">J\'entendis la voix du Seigneur, disant : Qui enverrai-je, et qui marchera <strong style=\"mso-bidi-font-weight: normal;\">pour nous ?</strong> Je r&eacute;pondis : Me voici, envoie-moi&nbsp;&raquo; <strong style=\"mso-bidi-font-weight: normal;\">Esa&iuml;e 6&nbsp;:8</strong></span></p>\r\n<p class=\"MsoListParagraphCxSpFirst\" style=\"margin-left: 0cm; mso-add-space: auto; text-align: justify; text-indent: 14.2pt; line-height: normal;\"><strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">2. L&rsquo;adoration de Dieu par les anges. </span></strong></p>\r\n<p class=\"MsoListParagraphCxSpMiddle\" style=\"margin-left: 0cm; mso-add-space: auto; text-align: justify; line-height: normal;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\'; mso-bidi-font-weight: bold;\">Le mot<strong> &laquo;&nbsp;Saint&nbsp;&raquo; </strong>r&eacute;p&eacute;t&eacute; trois fois indique<strong> qu&rsquo;&agrave; chacun des mots correspond un des &ecirc;tres divins </strong></span><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">&laquo;&nbsp;</span><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: FR;\">Ils criaient l\'un &agrave; l\'autre, et disaient : <strong style=\"mso-bidi-font-weight: normal;\">Saint, Saint, Saint</strong> est l\'&Eacute;ternel des arm&eacute;es ! Toute la terre est pleine de sa gloire ! &raquo; <strong style=\"mso-bidi-font-weight: normal;\">Esa&iuml;e 6&nbsp;:3</strong></span></p>\r\n<p class=\"MsoListParagraphCxSpMiddle\" style=\"margin-left: 0cm; mso-add-space: auto; text-indent: 14.2pt; line-height: normal;\"><strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\'; color: black;\">Les indices de la trinit&eacute; dans le Nouveau Testament</span></strong></p>\r\n<p class=\"MsoListParagraphCxSpMiddle\" style=\"margin-left: 0cm; mso-add-space: auto; text-align: justify; text-indent: 14.2pt; line-height: normal;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\'; color: black;\">1.<span style=\"mso-spacerun: yes;\">&nbsp; </span><strong style=\"mso-bidi-font-weight: normal;\">La manifestation des trois &ecirc;tres lors du bapt&ecirc;me de J&eacute;sus Christ</strong>.</span></p>\r\n<p class=\"MsoListParagraphCxSpLast\" style=\"margin-left: 0cm; mso-add-space: auto; text-align: justify; text-indent: 14.2pt; line-height: normal;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\'; color: black;\"><span style=\"mso-spacerun: yes;\">&nbsp;</span><strong>Matthieu 3:16-17 </strong>dit: &laquo;D&egrave;s que <strong>J&eacute;sus </strong>eut &eacute;t&eacute; baptis&eacute;, il sortit de l\'eau. Et voici, les cieux s\'ouvrirent, et il vit l\'<strong>Esprit </strong>de Dieu descendre comme <strong style=\"mso-bidi-font-weight: normal;\">une Colombe</strong> et venir sur lui. Et voici, une <strong>Voix </strong>fit entendre des cieux ces paroles : Celui-ci est mon Fils bien-aim&eacute;, en qui j\'ai mis toute mon affection. &raquo; Nous voyons ici <strong style=\"mso-bidi-font-weight: normal;\">J&eacute;sus</strong> qui est dans l&rsquo;eau, <strong style=\"mso-bidi-font-weight: normal;\">l&rsquo;Esprit</strong> qui descend sur lui sous forme d&rsquo;une colombe, et <strong style=\"mso-bidi-font-weight: normal;\">la voix de Dieu</strong> qui parle du haut des cieux. </span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify; text-indent: 14.2pt;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\'; color: black;\">2. <strong style=\"mso-bidi-font-weight: normal;\">La grande commission</strong>&nbsp;: les croyants sont baptis&eacute;s au nom de toute la trinit&eacute;.<span style=\"mso-spacerun: yes;\">&nbsp; </span><strong>Matthieu 28:19-20</strong>: &laquo;Allez, faites de toutes les nations des disciples, les baptisant au nom du <strong>P&egrave;re</strong>, du <strong>Fils </strong>et du <strong>Saint -Esprit</strong>, et enseignez-leur &agrave; observer tout ce que je vous ai prescrit.&nbsp;</span></p>\r\n<p class=\"MsoListParagraphCxSpFirst\" style=\"margin-left: 0cm; mso-add-space: auto; text-align: justify; text-indent: 14.2pt;\"><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\'; color: black;\">Et voici, je suis avec vous tous les jours, jusqu\'&agrave; la fin du monde. &raquo; <strong>Jean 14 :16-17</strong> : </span></p>\r\n<p class=\"MsoListParagraphCxSpMiddle\" style=\"margin-left: 0cm; mso-add-space: auto; text-align: justify;\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\'; color: black;\">La B&eacute;n&eacute;diction de Paul&nbsp;: </span></strong><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\'; color: black;\">le r&ocirc;le de chacun de trois personnes est mentionn&eacute;&nbsp;<strong style=\"mso-bidi-font-weight: normal;\">: la gr&acirc;ce du Seigneur J&eacute;sus, l&rsquo;amour de Dieu le P&egrave;re et la communion du Saint Esprit. <span style=\"mso-bidi-font-weight: bold;\">2 Corinthiens 13 :14</span></strong> : &laquo; Que la gr&acirc;ce du Seigneur <strong>J&eacute;sus-Christ</strong>, l\'amour de <strong>Dieu</strong>, et la communication du <strong>Saint -Esprit</strong>, soient avec vous tous !&raquo; </span></p>\r\n<p class=\"MsoListParagraphCxSpMiddle\" style=\"margin-left: 0cm; mso-add-space: auto; text-align: center; text-indent: 14.2pt;\" align=\"center\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\'; color: black;\">Les attributs de Dieu&nbsp;: Indices de la trinit&eacute;</span></strong></p>\r\n<p class=\"MsoListParagraphCxSpMiddle\" style=\"margin-left: 0cm; mso-add-space: auto; text-align: justify;\"><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\'; color: black;\">Les attributs d&eacute;crivent la nature et les caract&egrave;res de Dieu. Le P&egrave;re, le Fils et le Saint Esprit ont les m&ecirc;mes attributs.</span></p>\r\n<p class=\"MsoListParagraphCxSpMiddle\" style=\"margin-left: 0cm; mso-add-space: auto; text-align: justify; text-indent: 14.2pt;\"><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\'; color: black;\">1. Le P&egrave;re, le Fils et le Saint Esprit sont <strong style=\"mso-bidi-font-weight: normal;\">omniscients</strong> (la toute connaissance de Dieu) Psaumes 147&nbsp;:5, Colossiens 2&nbsp;:2-3, 1 Corinthiens 2&nbsp;:10-11)</span></p>\r\n<p class=\"MsoListParagraphCxSpMiddle\" style=\"margin-left: 0cm; mso-add-space: auto; text-align: justify; text-indent: 14.2pt;\"><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\'; color: black;\">2.<strong style=\"mso-bidi-font-weight: normal;\"> Omnipr&eacute;sents</strong>&nbsp;(la pr&eacute;sence de Dieu partout) : J&eacute;r&eacute;mie 23&nbsp;:24&nbsp;; Mathieu 28&nbsp;:20 Psaumes 139&nbsp;:7-10</span></p>\r\n<p class=\"MsoListParagraphCxSpMiddle\" style=\"margin-left: 0cm; mso-add-space: auto; text-align: justify; text-indent: 14.2pt;\"><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\'; color: black;\">3.</span><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\"> Omnipotents&nbsp;:</span></strong><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\"> (Dieu est Tout Puissant) Mathieu 19&nbsp;:26, Eph&eacute;siens 1&nbsp;:20-21, Luc 4&nbsp;:14</span></p>\r\n<p class=\"MsoListParagraphCxSpMiddle\" style=\"margin-left: 0cm; mso-add-space: auto; text-align: justify; text-indent: 14.2pt;\"><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">4. <strong style=\"mso-bidi-font-weight: normal;\">Eternit&eacute;</strong>&nbsp;: Psaumes 90&nbsp;:2, Mich&eacute;e 5&nbsp;:2&nbsp;; H&eacute;breux 9&nbsp;:14</span></p>\r\n<p class=\"MsoListParagraphCxSpMiddle\" style=\"margin-left: 0cm; mso-add-space: auto; text-align: justify; text-indent: 14.2pt;\"><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">5. <strong style=\"mso-bidi-font-weight: normal;\">Auto existence</strong> (Dieu existe par soi-m&ecirc;me parce qu&rsquo;il a la vie en lui-m&ecirc;me&nbsp;: Jean 5&nbsp;:26, jean 1&nbsp;:4. Romain 8&nbsp;:2 (Esprit de vie) </span></p>\r\n<p class=\"MsoListParagraphCxSpMiddle\" style=\"margin-left: 0cm; mso-add-space: auto;\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">Les actions divines sont associ&eacute;es aux trois comme preuves de la trinit&eacute;&nbsp;:</span></strong></p>\r\n<p class=\"MsoListParagraphCxSpMiddle\" style=\"margin-left: 0cm; mso-add-space: auto; text-align: justify; text-indent: 14.2pt;\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">1. La cr&eacute;ation est l&rsquo;&oelig;uvre du p&egrave;re, du fils et du Saint Esprit&nbsp;; Gen&egrave;se 1&nbsp;:26,&nbsp;Colossiens 1&nbsp;:16, job 33&nbsp;:4&nbsp;; psaumes 104&nbsp;:30.</span></strong></p>\r\n<p class=\"MsoListParagraphCxSpMiddle\" style=\"margin-left: 0cm; mso-add-space: auto; text-align: center; text-indent: 14.2pt;\" align=\"center\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">2. La r&eacute;surrection est associ&eacute;e aux trois. </span></strong></p>\r\n<p class=\"MsoListParagraphCxSpLast\" style=\"margin-left: 0cm; mso-add-space: auto;\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">1 Corinthiens 6&nbsp;:14&nbsp;; Jean 11&nbsp;:25, Romain 8&nbsp;:11.</span></strong></p>\r\n<p class=\"MsoNormal\"><span lang=\"FR\" style=\"font-size: 10.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%;\">&nbsp;</span></p>\r\n<p class=\"MsoNormal\"><span lang=\"FR\">&nbsp;</span></p>', 2, '2025-10-23 10:38:04'),
(9, 1, 'LEÇON N°3 : LE PERE', '<p class=\"MsoNormal\" style=\"text-align: center;\" align=\"center\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-size: 14.0pt; mso-bidi-font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">LE&Ccedil;ON N&deg; 3 : LE PERE</span></strong></p>\r\n<p class=\"MsoListParagraph\" style=\"margin: 0cm; margin-bottom: .0001pt; mso-add-space: auto; text-align: justify; text-indent: 14.2pt;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">&laquo; Dieu, le P&egrave;re &eacute;ternel, est le cr&eacute;ateur, la Source, le Soutien et le Souverain de toute la cr&eacute;ation. Il est juste et saint, mis&eacute;ricordieux et compatissant, lent &agrave; la col&egrave;re, riche en bienveillance et en fid&eacute;lit&eacute;. Les vertus et les facult&eacute;s manifest&eacute;es par le Fils et le Saint-Esprit sont aussi r&eacute;v&eacute;latrices du P&egrave;re &raquo;. Beaucoup de gens comprennent l&rsquo;importance de la mission de Christ pour le salut de l&rsquo;homme et le r&ocirc;le du Saint-Esprit dans la vie du chr&eacute;tien, mais sans comprendre parfaitement ce que le P&egrave;re fait pour nous. Il y a m&ecirc;me ceux qui disent que Dieu le P&egrave;re de l&rsquo;Ancien Testament &eacute;tait un Dieu de vengeance, alors que celui du Nouveau Testament est plein de gr&acirc;ce ! Voyons un peu Dieu le P&egrave;re &agrave; travers la Bible. </span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: center;\" align=\"center\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">(1). Caract&egrave;res de Dieu le P&egrave;re dans l&rsquo;Ancien Testament</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: center;\" align=\"center\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Un Dieu de mis&eacute;ricorde</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Exode 34 :6-7</span></strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\"> : &laquo; Et l\'&Eacute;ternel passa devant lui, et s\'&eacute;cria: L\'&Eacute;ternel, l\'&Eacute;ternel, Dieu mis&eacute;ricordieux et compatissant, lent &agrave; la col&egrave;re, riche en bont&eacute; et en fid&eacute;lit&eacute;, qui conserve son amour jusqu\'&agrave; mille g&eacute;n&eacute;rations, qui pardonne l\'iniquit&eacute;, la r&eacute;bellion et le p&eacute;ch&eacute;, mais qui ne tient point le coupable pour innocent, et qui punit l\'iniquit&eacute; des p&egrave;res sur les enfants et sur les enfants des enfants jusqu\'&agrave; la troisi&egrave;me et &agrave; la quatri&egrave;me g&eacute;n&eacute;ration!&raquo; </span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: center;\" align=\"center\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Un Dieu pr&egrave;s des gens</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify;\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Exode 25 :8</span></strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\"> : &laquo; Ils me feront un sanctuaire, et j\'habiterai au milieu d\'eux. &raquo;. Psaumes 46 :1 : &laquo; Dieu est pour nous un refuge et un appui, Un secours qui ne manque jamais dans la d&eacute;tresse. &raquo; &nbsp;</span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify; text-indent: 14.2pt;\"><strong><span lang=\"FR\" style=\"font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">Psaumes 125 :2 :</span></strong><span lang=\"FR\" style=\"font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\'; mso-bidi-font-weight: bold;\"> &laquo; Des montagnes entourent J&eacute;rusalem ; Ainsi l\'&Eacute;ternel entoure son peuple, D&egrave;s maintenant et &agrave; jamais. &raquo; <strong>Psaumes 55 :23</strong> : &laquo; Remets ton sort &agrave; l\'&Eacute;ternel, et il te soutiendra, Il ne laissera jamais chanceler le juste. &raquo; </span><strong><span lang=\"FR\" style=\"font-size: 10.0pt; mso-bidi-font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">Psaumes 146 :7-9</span></strong><span lang=\"FR\" style=\"font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\'; mso-bidi-font-weight: bold;\"> : &laquo; Il [l&rsquo;Eternel] fait droit aux opprim&eacute;s ; Il donne du pain aux affam&eacute;s ; L\'&Eacute;ternel d&eacute;livre les captifs ; L\'&Eacute;ternel ouvre les yeux des aveugles ; L\'&Eacute;ternel redresse ceux qui sont courb&eacute;s ; L\'&Eacute;ternel aime les justes. L\'&Eacute;ternel prot&egrave;ge les &eacute;trangers, Il soutient l\'orphelin et la veuve, Mais il renverse la voie des m&eacute;chants. &raquo;</span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: center;\" align=\"center\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Un Dieu qui pardonne les p&eacute;ch&eacute;s<span style=\"mso-spacerun: yes;\">&nbsp; </span></span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify; text-indent: 14.2pt;\"><strong><span lang=\"FR\" style=\"font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">Psaumes 51 :1-6 :</span></strong><span lang=\"FR\" style=\"font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\'; mso-bidi-font-weight: bold;\"> &laquo; Psaume de David. Lorsque Nathan, le proph&egrave;te, vint &agrave; lui, apr&egrave;s que David fut all&eacute; vers Bath-Sch&eacute;ba. O Dieu ! aie piti&eacute; de moi dans ta bont&eacute; ; Selon ta grande mis&eacute;ricorde, efface mes transgressions ; Lave-moi compl&egrave;tement de mon iniquit&eacute;, Et purifie-moi de mon p&eacute;ch&eacute;. Car je reconnais mes transgressions, Et mon p&eacute;ch&eacute; est constamment devant moi. J\'ai p&eacute;ch&eacute; contre toi seul, Et j\'ai fait ce qui est mal &agrave; tes yeux, En sorte que tu seras juste dans ta sentence, Sans reproche dans ton jugement. &raquo;</span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify;\"><strong><span lang=\"FR\" style=\"font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">Mich&eacute;e 7:18-19</span></strong><span lang=\"FR\"> : &laquo;</span><span lang=\"FR\" style=\"font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\'; mso-bidi-font-weight: bold;\">Quel Dieu est semblable &agrave; toi, Qui pardonnes l\'iniquit&eacute;, qui oublies les p&eacute;ch&eacute;s Du reste de ton h&eacute;ritage ? Il ne garde pas sa col&egrave;re &agrave; toujours, Car il prend plaisir &agrave; la mis&eacute;ricorde. Il aura encore compassion de nous,&nbsp;</span></p>\r\n<p class=\"MsoListParagraph\" style=\"margin: 0cm; margin-bottom: .0001pt; mso-add-space: auto; text-align: justify;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Il mettra sous ses pieds nos iniquit&eacute;s ; Tu jetteras au fond de la mer tous leurs p&eacute;ch&eacute;s. &raquo;</span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: center;\" align=\"center\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-size: 10.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">(</span></strong><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">2). Caract&egrave;res de Dieu le P&egrave;re dans le nouveau testament</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Le Dieu de l&rsquo;Ancien Testament est le m&ecirc;me que celui du Nouveau Testament.<span style=\"mso-spacerun: yes;\">&nbsp; </span>Il est :</span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: center;\" align=\"center\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\"><span style=\"mso-spacerun: yes;\">&nbsp;</span>Le P&egrave;re de toute la cr&eacute;ation.</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><strong><span lang=\"FR\" style=\"font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">1 Corinthiens 8 :6 :</span></strong><span lang=\"FR\"> &laquo;</span><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\"> Il n\'y a qu\'un seul Dieu, le P&egrave;re, de qui viennent toutes choses et pour qui nous sommes, et un seul Seigneur, J&eacute;sus-Christ, par qui sont toutes choses et par qui nous sommes. &raquo;</span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\">Eph&eacute;siens 3 :14-15 :</span></strong><span lang=\"FR\"> &laquo; &Agrave; cause de cela, je fl&eacute;chis les genoux devant le P&egrave;re, duquel tire son nom toute famille dans les cieux et sur la terre. &raquo; </span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: center;\" align=\"center\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">La r&eacute;v&eacute;lation parfaite de Dieu le P&egrave;re s&rsquo;est faite par J&eacute;sus-Christ.</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><span lang=\"FR\"><span style=\"mso-spacerun: yes;\">&nbsp;</span><strong style=\"mso-bidi-font-weight: normal;\">Jean 1 :18</strong> : &laquo; Personne n\'a jamais vu Dieu ; le Fils unique, qui est dans le sein du P&egrave;re, est celui qui l\'a fait conna&icirc;tre. &raquo; <strong style=\"mso-bidi-font-weight: normal;\">Jean 14 :9-10</strong> : &laquo; Celui qui m&rsquo;a vu a vu le P&egrave;re ; comment dis-tu: Montre-nous le P&egrave;re? Ne crois-tu pas que je suis dans le P&egrave;re, et que le P&egrave;re est en moi ? Les paroles que je vous dis, je ne les dis pas de moi-m&ecirc;me ; et le P&egrave;re qui demeure en moi, c\'est lui qui fait les &oelig;uvres.&raquo; Celui qui connait J&eacute;sus connait le P&egrave;re, celui qui voit J&eacute;sus voit le P&egrave;re, J&eacute;sus est le &laquo;&nbsp;<em style=\"mso-bidi-font-style: normal;\">reflet</em>&nbsp;&raquo; ou &laquo;&nbsp;<em style=\"mso-bidi-font-style: normal;\">l&rsquo;empreinte</em>&nbsp;&raquo; de Dieu le P&egrave;re.</span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Un Dieu d&rsquo;amour</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify;\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\">Jean 3 :16</span></strong><span lang=\"FR\"> &laquo; Dieu a tant aim&eacute; le monde qu\'il a donn&eacute; son Fils unique, afin que quiconque croit en lui ne p&eacute;risse point, mais qu\'il ait la vie &eacute;ternelle. &raquo;</span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify;\"><span lang=\"FR\">&nbsp;</span></p>', 3, '2025-10-23 11:12:55');
INSERT INTO `lecons` (`id`, `categorie_id`, `titre`, `contenu`, `ordre`, `date_creation`) VALUES
(10, 1, 'LEÇON N°4 : LE FILS', '<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: center;\" align=\"center\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"mso-bidi-font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">LE&Ccedil;ON N&deg; 4 : LE FILS</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><span lang=\"FR\" style=\"mso-bidi-font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">&laquo; Dieu, le Fils &eacute;ternel, s\'est incarn&eacute; en J&eacute;sus Christ. Par lui, tout a &eacute;t&eacute; cr&eacute;&eacute; ; par lui, le caract&egrave;re de Dieu est r&eacute;v&eacute;l&eacute;, le salut de l\'humanit&eacute; est accompli et le monde est jug&eacute;. Eternellement et v&eacute;ritablement Dieu, il est aussi devenu v&eacute;ritablement homme, J&eacute;sus le Christ. Il est n&eacute; de la vierge Marie. Il a v&eacute;cu et a &eacute;t&eacute; soumis &agrave; la tentation en tant qu\'homme, mais il a donn&eacute; l\'exemple parfait de la justice et de l\'amour de Dieu. Ses miracles ont attest&eacute; sa divinit&eacute; et l\'ont confirm&eacute; comme le Messie promis. Il a souffert et il est mort de son plein gr&eacute; sur la croix pour nos p&eacute;ch&eacute;s et &agrave; notre place, il est ressuscit&eacute; des morts et il est mont&eacute; au ciel pour exercer un minist&egrave;re en notre faveur dans le sanctuaire c&eacute;leste. Il reviendra en gloire pour apporter la d&eacute;livrance finale &agrave; son peuple et la restauration de toutes choses. &raquo; </span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify; margin: 12.0pt 0cm .0001pt 0cm;\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"mso-bidi-font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">Les preuves Bibliques de la divinit&eacute; de Christ.</span></strong><span lang=\"FR\" style=\"mso-bidi-font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\"> <strong style=\"mso-bidi-font-weight: normal;\"><em style=\"mso-bidi-font-style: normal;\">Christ a des attributs divins :</em></strong></span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><span lang=\"FR\" style=\"mso-bidi-font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">Il est <strong style=\"mso-bidi-font-weight: normal;\">omnipotent </strong>: <strong style=\"mso-bidi-font-weight: normal;\">Matthieu28 :18 :</strong> &laquo; Tout pouvoir m&rsquo;a &eacute;t&eacute; donn&eacute; dans le ciel et sur la terre.&raquo; Il est <strong style=\"mso-bidi-font-weight: normal;\">omniscient</strong> : <strong style=\"mso-bidi-font-weight: normal;\">Colossiens 2:3</strong>: Christ est le &laquo;myst&egrave;re dans lequel sont cach&eacute;s tous les tr&eacute;sors de la sagesse et de la science.&raquo;</span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><span lang=\"FR\" style=\"mso-bidi-font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">Il est <strong style=\"mso-bidi-font-weight: normal;\">omnipr&eacute;sent</strong> : <strong style=\"mso-bidi-font-weight: normal;\">Matthieu 18 :20</strong> : &laquo;Car l&agrave; o&ugrave; deux ou trois sont assembl&eacute;s en mon nom, je suis au milieu d\'eux&raquo;; <strong style=\"mso-bidi-font-weight: normal;\">Matthieu 28:20:</strong> &laquo;Et voici, je suis avec vous tous les jours, jusqu\'&agrave; la fin du monde.&raquo;</span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><span lang=\"FR\" style=\"mso-bidi-font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">Il <strong style=\"mso-bidi-font-weight: normal;\">ne change pas</strong> : <strong style=\"mso-bidi-font-weight: normal;\">H&eacute;breux 13 :8</strong> : &laquo; J&eacute;sus-Christ est le m&ecirc;me hier, aujourd\'hui, et &eacute;ternellement. &raquo; Il est &eacute;ternel : <strong style=\"mso-bidi-font-weight: normal;\">Esa&iuml;e 9 :6</strong>: &laquo;Car un enfant nous est n&eacute;, un fils nous est donn&eacute;,</span><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\"> on l\'appellera Admirable, Conseiller, Dieu puissant, P&egrave;re &eacute;ternel, Prince de la paix &raquo;;&nbsp;</span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify; line-height: 107%;\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; font-family: \'Times New Roman\',\'serif\';\">Mich&eacute;e 5:2</span></strong><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; font-family: \'Times New Roman\',\'serif\';\">: &laquo;Et toi, Bethlehem Ephrata, Petite entre les milliers de Juda, De toi sortira pour moi Celui qui dominera sur Isra&euml;l, Et dont l\'origine remonte aux temps anciens, Aux jours de l\'&eacute;ternit&eacute;.&raquo;</span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: center;\" align=\"center\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-size: 10.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">Christ a des pouvoirs divins :</span></strong><span lang=\"FR\" style=\"font-size: 10.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\"> <strong style=\"mso-bidi-font-weight: normal;\">la vie en lui-m&ecirc;me</strong></span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\"><span style=\"mso-spacerun: yes;\">&nbsp;</span><strong style=\"mso-bidi-font-weight: normal;\">Jean 11 :25</strong> : &laquo; Je suis la r&eacute;surrection et la vie. &raquo; </span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Cr&eacute;ateur ; Colossiens 1 :16</span></strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\"> : &laquo; En lui ont &eacute;t&eacute; cr&eacute;&eacute;es toutes les choses qui sont dans les cieux et sur la terre, les visibles et les invisibles, tr&ocirc;nes, dignit&eacute;s, dominations, autorit&eacute;s. Tout a &eacute;t&eacute; cr&eacute;&eacute; par lui et pour lui. &raquo;&nbsp;;<strong style=\"mso-bidi-font-weight: normal;\"> Jean 1 :1-3. </strong></span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Il a le pouvoir de pardonner le p&eacute;ch&eacute;</span></strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\"> (<strong style=\"mso-bidi-font-weight: normal;\">Matthieu 9 :6 ; Marc 2 :5-7).</strong> <strong style=\"mso-bidi-font-weight: normal;\">Christ a des noms divins :</strong> <strong style=\"mso-bidi-font-weight: normal;\">Emmanuel</strong> signifie Dieu avec nous (<strong style=\"mso-bidi-font-weight: normal;\">Matthieu 1 :23</strong>). </span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: center; line-height: 150%;\" align=\"center\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Les ap&ocirc;tres ont reconnu la divinit&eacute; de J&eacute;sus.</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\"><span style=\"mso-spacerun: yes;\">&nbsp;</span>Jean dit <strong style=\"mso-bidi-font-weight: normal;\">en Jean 1 :1,14</strong> : &laquo; Au commencement &eacute;tait la Parole, et la Parole &eacute;tait avec Dieu, et la Parole &eacute;tait Dieu&hellip;<span style=\"mso-spacerun: yes;\">&nbsp; </span>Et la parole a &eacute;t&eacute; faite chair, et elle a habit&eacute; parmi nous, pleine de gr&acirc;ce et de v&eacute;rit&eacute; ; et nous avons contempl&eacute; sa gloire, une gloire comme la gloire du Fils unique venu du P&egrave;re. &raquo; <strong style=\"mso-bidi-font-weight: normal;\">En Jean 20:28,</strong> <strong style=\"mso-bidi-font-weight: normal;\">Thomas </strong>s&rsquo;est adress&eacute; &agrave; Christ ressuscit&eacute; disant: &laquo;Mon Seigneur et mon Dieu!&raquo; <strong style=\"mso-bidi-font-weight: normal;\">En Romains 9:5, Paul</strong> l&rsquo;appelle &laquo;le Christ, qui est au-dessus de toutes choses, Dieu b&eacute;nit &eacute;ternellement.&raquo; Il ajoute, en <strong style=\"mso-bidi-font-weight: normal;\">Colossiens 2:9</strong>, qu&rsquo;&laquo;en lui [Christ] habite corporellement toute la pl&eacute;nitude de la divinit&eacute;.&raquo; <strong style=\"mso-bidi-font-weight: normal;\">H&eacute;breu 1:8-9</strong> d&eacute;clare &agrave; son sujet: &laquo;Mais il a dit au Fils: Ton tr&ocirc;ne, &ocirc; Dieu, est &eacute;ternel&hellip;&ocirc; Dieu, ton Dieu t&rsquo;a oint D\'une huile de joie au-dessus de tes &eacute;gaux.&raquo;&nbsp;</span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify; text-indent: 35.4pt;\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">J&eacute;sus lui-m&ecirc;me disait</span></strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\"> : &laquo; Moi et le P&egrave;re nous sommes un &raquo; <strong style=\"mso-bidi-font-weight: normal;\">(Jean 10 :30).</strong> &laquo; <strong style=\"mso-bidi-font-weight: normal;\">J&eacute;sus acceptait l&rsquo;adoration en tant que Dieu</strong>. <strong style=\"mso-bidi-font-weight: normal;\">(Matthieu 4 :10; 15:25; Luc 5:8;</strong> <strong style=\"mso-bidi-font-weight: normal;\">24:52; Jean 5:23; 20:28; 1Corinthiens 1:1-2; Philippiens 2:10; H&eacute;breux 1:6</strong>&hellip;)</span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Contrairement aux ap&ocirc;tres <strong style=\"mso-bidi-font-weight: normal;\">(Actes 10 :25-26 ; 14 :10-15</strong>) et m&ecirc;me aux anges <strong style=\"mso-bidi-font-weight: normal;\">(Apocalypse 19 :10 ; 22 :8,9)</strong> qui n&rsquo;acceptaient pas d&rsquo;&ecirc;tre ador&eacute;s, Or l&rsquo;adoration est due &agrave; Dieu et &agrave; Dieu seul <strong style=\"mso-bidi-font-weight: normal;\">(Matthieu 4:9-10; Apocalypse 19:10).</strong> <strong style=\"mso-bidi-font-weight: normal;\">En Apocalypse 5, 26</strong> <strong style=\"mso-bidi-font-weight: normal;\">l&rsquo;Agneau de Dieu (Christ)</strong> est ador&eacute; par les 24 vieillards et les 4 &ecirc;tres vivants de la m&ecirc;me mani&egrave;re que l&rsquo;est Dieu le P&egrave;re.</span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: center;\" align=\"center\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Le Fils premier-n&eacute; de toute la cr&eacute;ation.</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">&nbsp;</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify; text-indent: 35.4pt;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Il est l\'image du Dieu invisible, le premier-n&eacute; de toute la cr&eacute;ation. <strong style=\"mso-bidi-font-weight: normal;\">(Col 1&nbsp;:15).</strong> La Bible regorge des personnages qui n&rsquo;&eacute;taient pas des premiers- n&eacute;s biologiquement mais que Dieu les appelle premiers -n&eacute;s. <strong style=\"mso-bidi-font-weight: normal;\">Jacob ou Isra&euml;l</strong> <strong style=\"mso-bidi-font-weight: normal;\">(Ex 4&nbsp;:22)</strong>. <strong style=\"mso-bidi-font-weight: normal;\">Ephra&iuml;m (J&eacute;r&eacute;mie 31&nbsp;:9).</strong> (<strong style=\"mso-bidi-font-weight: normal;\">Psaumes 89&nbsp;:3,27). Le mot premier-n&eacute; signifie &eacute;l&eacute;vation o&ugrave; &eacute;lever quelqu&rsquo;un (Psaumes 89&nbsp;:27). </strong>Dans le but de nous sauver<strong style=\"mso-bidi-font-weight: normal;\"> </strong>J&eacute;sus a &eacute;t&eacute; abaiss&eacute; pour un peu de temps <strong style=\"mso-bidi-font-weight: normal;\">(H&eacute;breux 2&nbsp;:9)</strong> et apr&egrave;s ce grand travail il demande qu&rsquo;il soit &eacute;lev&eacute; &agrave; la gloire qu&rsquo;il avait avant la cr&eacute;ation. <strong style=\"mso-bidi-font-weight: normal;\">(Jean 17&nbsp;:4-5</strong></span><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">). </span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">J&eacute;sus fut &eacute;lev&eacute; et il a &eacute;t&eacute; ainsi appel&eacute; premier-n&eacute;.</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">&nbsp;</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify; text-indent: 35.4pt;\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">Le Fils engendr&eacute;</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">(<strong style=\"mso-bidi-font-weight: normal;\">H&eacute;breux 1&nbsp;:5</strong>,&nbsp;<strong style=\"mso-bidi-font-weight: normal;\">H&eacute;breux 5&nbsp;:5, Psaumes 2&nbsp;:7</strong>).<span style=\"mso-spacerun: yes;\">&nbsp; </span>Quand est ce que le fils fut engendr&eacute;&nbsp;? La Bible r&eacute;pond en disant en Actes 13&nbsp;:32-33. Selon ce texte l&rsquo;expression <strong style=\"mso-bidi-font-weight: normal;\">Le Fils engendr&eacute;&nbsp;:</strong> signifie r&eacute;surrection du Christ.</span></p>', 4, '2025-10-23 11:46:53'),
(11, 1, 'LEÇON N°5 : LE SAINT-ESPRIT', '<p class=\"MsoNormal\" style=\"text-align: center;\" align=\"center\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"mso-bidi-font-size: 10.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">LE&Ccedil;ON N&deg; 5 : LE SAINT-ESPRIT</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><span lang=\"FR\" style=\"mso-bidi-font-size: 10.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">&laquo; Dieu, l\'Esprit &eacute;ternel, a pris avec le P&egrave;re et le Fils une part active &agrave; la cr&eacute;ation, &agrave; l\'incarnation et &agrave; la r&eacute;demption. Il a inspir&eacute; les &eacute;crivains de la Bible. Il a rempli de puissance la vie du Christ. Il attire et persuade les &ecirc;tres humains ; ceux qui r&eacute;pondent favorablement, il les r&eacute;g&eacute;n&egrave;re et les transforme &agrave; l\'image de Dieu. Envoy&eacute; par le P&egrave;re et le Fils pour &ecirc;tre toujours avec ses enfants, il dispense ses dons spirituels &agrave; l\'Eglise, il donne la puissance n&eacute;cessaire pour rendre t&eacute;moignage au Christ, et en harmonie avec les Ecritures il conduit dans toute v&eacute;rit&eacute;. &raquo;</span></p>\r\n<p class=\"Default\" style=\"text-align: center;\" align=\"center\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-size: 10.0pt; font-family: \'Times New Roman\',\'serif\'; color: windowtext;\">Divinit&eacute; du Saint-Esprit</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify; line-height: normal; mso-layout-grid-align: none; text-autospace: none;\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"mso-bidi-font-size: 10.0pt; font-family: \'Times New Roman\',\'serif\'; color: black;\">Le Saint-Esprit a les attributs divins </span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify; line-height: normal; mso-layout-grid-align: none; text-autospace: none;\"><span lang=\"FR\" style=\"mso-bidi-font-size: 10.0pt; font-family: \'Times New Roman\',\'serif\'; color: black;\">1. Le Saint-Esprit est <strong>omniscient (</strong>la toute connaissance de Dieu) 1 Corinthiens 2 :10-11) </span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify; line-height: normal; mso-layout-grid-align: none; text-autospace: none;\"><span lang=\"FR\" style=\"mso-bidi-font-size: 10.0pt; font-family: \'Times New Roman\',\'serif\'; color: black;\">2. Il est <strong>Omnipr&eacute;sent </strong>(la pr&eacute;sence de Dieu partout) : Psaumes 139 :7-10 </span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify; line-height: normal; mso-layout-grid-align: none; text-autospace: none;\"><span lang=\"FR\" style=\"mso-bidi-font-size: 10.0pt; font-family: \'Times New Roman\',\'serif\'; color: black;\">3. Il est <strong style=\"mso-bidi-font-weight: normal;\">Omnipotent<span style=\"mso-bidi-font-weight: bold;\"> : </span></strong>(Dieu est Tout Puissant) Luc 4 :14 </span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify; line-height: normal; mso-layout-grid-align: none; text-autospace: none;\"><span lang=\"FR\" style=\"mso-bidi-font-size: 10.0pt; font-family: \'Times New Roman\',\'serif\'; color: black;\">4. Il est <strong>Eternel :</strong> H&eacute;breux 9 :14 </span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify; line-height: normal; mso-layout-grid-align: none; text-autospace: none;\"><span lang=\"FR\" style=\"mso-bidi-font-size: 10.0pt; font-family: \'Times New Roman\',\'serif\'; color: black;\">5. Il a l&rsquo;<strong>Auto existence </strong>(Dieu existe par soi-m&ecirc;me parce qu&rsquo;il a la vie en lui-m&ecirc;me) <strong style=\"mso-bidi-font-weight: normal;\">Romain 8 :2</strong> (Esprit de vie) </span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: center; line-height: normal; mso-layout-grid-align: none; text-autospace: none;\" align=\"center\"><strong><span lang=\"FR\" style=\"font-size: 10.0pt; font-family: \'Times New Roman\',\'serif\'; color: black;\">Le Saint-Esprit participe aux actions divines</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; line-height: normal; mso-layout-grid-align: none; text-autospace: none;\"><strong><span lang=\"FR\" style=\"font-size: 10.0pt; font-family: \'Times New Roman\',\'serif\'; color: black;\">1. </span></strong><strong><span lang=\"FR\" style=\"font-size: 9.0pt; mso-bidi-font-size: 10.0pt; font-family: \'Times New Roman\',\'serif\'; color: black;\">Saint-Esprit avait particip&eacute; &agrave; la cr&eacute;ation job 33 :4</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; line-height: normal; mso-layout-grid-align: none; text-autospace: none;\"><strong><span lang=\"FR\" style=\"font-size: 10.0pt; font-family: \'Times New Roman\',\'serif\'; color: black;\">2. Saint-Esprit ressuscite les morts </span></strong><strong><span lang=\"FR\" style=\"font-size: 10.0pt; font-family: \'Times New Roman\',\'serif\';\">Romain 8 :11.</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify; line-height: normal; mso-layout-grid-align: none; text-autospace: none;\"><strong><span lang=\"FR\" style=\"mso-bidi-font-size: 10.0pt; font-family: \'Times New Roman\',\'serif\';\">En Actes 5:3-4</span></strong><span lang=\"FR\" style=\"mso-bidi-font-size: 10.0pt; font-family: \'Times New Roman\',\'serif\';\">: &laquo;Pierre lui dit: Ananias, pourquoi Satan a-t-il rempli ton c&oelig;ur, au point que tu mentes au <strong style=\"mso-bidi-font-weight: normal;\">Saint-Esprit,</strong> et que tu aies retenu une partie du prix du champ? S\'il n\'e&ucirc;t pas &eacute;t&eacute; vendu, ne te restait-il pas ? Et, apr&egrave;s qu\'il a &eacute;t&eacute; vendu, le prix n\'&eacute;tait-il pas &agrave; ta disposition ? Comment as-tu pu mettre en ton c&oelig;ur un pareil dessein ? Ce n\'est pas &agrave; des hommes que tu as menti, mais &agrave; <strong style=\"mso-bidi-font-weight: normal;\">Dieu</strong>.&raquo; Quand Ananias a menti au Saint-Esprit, il n&rsquo;a pas menti aux hommes mais plut&ocirc;t &agrave; Dieu, le Saint-Esprit.</span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">&nbsp;</span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: center;\" align=\"center\"><strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Personnalit&eacute; du Saint-Esprit</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\'; mso-bidi-font-weight: bold;\">Certaines personnes pensent que le Saint-Esprit n&rsquo;est qu&rsquo;une force et ils nient sa personnalit&eacute;. Cette id&eacute;e est fausse car la Bible a beaucoup de passages qui montrent des indices de la personnalit&eacute; du Saint-Esprit. <strong>Il poss&egrave;de les facult&eacute;s d&rsquo;une personnalit&eacute; normale</strong>&nbsp;:</span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify; text-indent: -9.0pt; mso-list: l0 level1 lfo1; margin: 0cm 4.55pt .0001pt 0cm;\"><!-- [if !supportLists]--><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\';\"><span style=\"mso-list: Ignore;\">1.<span style=\"font: 7.0pt \'Times New Roman\';\"> </span></span></span><!--[endif]--><strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Il entend</span></strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\'; mso-bidi-font-weight: bold;\"> &laquo;&nbsp;</span><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Quand le consolateur sera venu, l\'Esprit de v&eacute;rit&eacute;, il vous conduira dans toute la v&eacute;rit&eacute; ; car il ne parlera pas de lui-m&ecirc;me, mais il dira tout ce qu\'il aura entendu, et il vous annoncera les choses &agrave; venir.&nbsp;&raquo; (<strong style=\"mso-bidi-font-weight: normal;\">Jean 16&nbsp;:13</strong>)</span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify; text-indent: -9.0pt; mso-list: l0 level1 lfo1; margin: 0cm 4.55pt .0001pt 4.5pt;\"><!-- [if !supportLists]--><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-bidi-font-weight: bold;\"><span style=\"mso-list: Ignore;\">2.<span style=\"font: 7.0pt \'Times New Roman\';\"> </span></span></span><!--[endif]--><strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Il parle &laquo;&nbsp;</span></strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">car ce n\'est pas vous qui parlerez, c\'est l\'Esprit de votre P&egrave;re qui parlera en vous.&nbsp;&raquo; (<strong style=\"mso-bidi-font-weight: normal;\">Mattieu 10&nbsp;:20</strong>)</span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify; text-indent: -9.0pt; mso-list: l0 level1 lfo1; margin: 0cm 4.55pt .0001pt 4.5pt;\"><!-- [if !supportLists]--><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-bidi-font-weight: bold;\"><span style=\"mso-list: Ignore;\">3.<span style=\"font: 7.0pt \'Times New Roman\';\"> </span></span></span><!--[endif]--><strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Il enseigne &laquo;&nbsp;</span></strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Mais le consolateur, l\'Esprit Saint, que le P&egrave;re enverra en mon nom, vous enseignera toutes choses, et vous rappellera tout ce que je vous ai dit&nbsp;&raquo; (<strong style=\"mso-bidi-font-weight: normal;\">Jean 14&nbsp;:26</strong>)</span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify; text-indent: -9.0pt; mso-list: l0 level1 lfo1; margin: 0cm 4.55pt .0001pt 4.5pt;\"><!-- [if !supportLists]--><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-bidi-font-weight: bold;\"><span style=\"mso-list: Ignore;\">4.<span style=\"font: 7.0pt \'Times New Roman\';\"> </span></span></span><!--[endif]--><strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Il aime</span></strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\'; mso-bidi-font-weight: bold;\"> &laquo;&nbsp;</span><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Je vous exhorte, fr&egrave;res, par notre Seigneur J&eacute;sus Christ et par l\'amour de l\'Esprit, &agrave; combattre avec moi, en adressant &agrave; Dieu des pri&egrave;res en ma faveur&nbsp;&raquo; (<strong style=\"mso-bidi-font-weight: normal;\">Romain 15&nbsp;:30</strong>)</span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify; text-indent: -9.0pt; mso-list: l0 level1 lfo1; margin: 0cm 4.55pt .0001pt 4.5pt;\"><!-- [if !supportLists]--><strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\';\"><span style=\"mso-list: Ignore;\">5.<span style=\"font: 7.0pt \'Times New Roman\';\"> </span></span></span></strong><!--[endif]--><strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Il console &laquo;&nbsp;</span></strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Et moi, je prierai le P&egrave;re, et il vous donnera un autre consolateur, afin qu\'il demeure &eacute;ternellement avec vous&nbsp;&raquo; (<strong style=\"mso-bidi-font-weight: normal;\">Jean14&nbsp;:16</strong>)</span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify; text-indent: -9.0pt; mso-list: l0 level1 lfo1; margin: 0cm 4.55pt .0001pt 4.5pt;\"><!-- [if !supportLists]--><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\';\"><span style=\"mso-list: Ignore;\">6.<span style=\"font: 7.0pt \'Times New Roman\';\"> </span></span></span><!--[endif]--><strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Il prie et interc&egrave;de &laquo;&nbsp;</span></strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">De m&ecirc;me aussi l\'Esprit nous aide dans notre faiblesse, car nous ne savons pas ce qu\'il nous convient de demander dans nos pri&egrave;res. Mais l\'Esprit lui-m&ecirc;me interc&egrave;de par des soupirs inexprimables ; et celui qui sonde les c&oelig;urs conna&icirc;t quelle est la pens&eacute;e de l\'Esprit, parce que c\'est selon Dieu qu\'il interc&egrave;de en faveur des saints&nbsp;&raquo; </span><span lang=\"FR\" style=\"font-size: 10.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">(<strong style=\"mso-bidi-font-weight: normal;\">Romain 8 :26-27)&nbsp;</strong></span></p>\r\n<p class=\"MsoListParagraphCxSpFirst\" style=\"mso-add-space: auto; text-align: justify; text-indent: -9.0pt; line-height: normal; mso-list: l1 level1 lfo2; tab-stops: 0cm; mso-layout-grid-align: none; text-autospace: none; margin: 0cm 0cm .0001pt 9.0pt;\"><!-- [if !supportLists]--><strong><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\';\"><span style=\"mso-list: Ignore;\">7.</span></span></strong><!--[endif]--><strong><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; font-family: \'Times New Roman\',\'serif\';\">Il a une volont&eacute; &laquo;&nbsp;</span></strong><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; font-family: \'Times New Roman\',\'serif\'; mso-bidi-font-weight: bold;\">Un seul et m&ecirc;me Esprit op&egrave;re toutes ces choses, les distribuant &agrave; chacun en particulier comme il veut.&nbsp;&raquo; </span></p>\r\n<p class=\"MsoListParagraphCxSpMiddle\" style=\"mso-add-space: auto; text-align: justify; line-height: normal; tab-stops: 0cm; mso-layout-grid-align: none; text-autospace: none; margin: 0cm 0cm .0001pt 9.0pt;\"><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; font-family: \'Times New Roman\',\'serif\'; mso-bidi-font-weight: bold;\">(<strong>1 Corinthiens 12&nbsp;:11</strong>)</span></p>\r\n<p class=\"MsoListParagraphCxSpLast\" style=\"mso-add-space: auto; text-align: justify; text-indent: -13.5pt; line-height: normal; mso-list: l1 level1 lfo2; tab-stops: 0cm; mso-layout-grid-align: none; text-autospace: none; margin: 0cm 0cm .0001pt 13.5pt;\"><!-- [if !supportLists]--><strong><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\';\"><span style=\"mso-list: Ignore;\">8.<span style=\"font: 7.0pt \'Times New Roman\';\">&nbsp;&nbsp; </span></span></span></strong><!--[endif]--><strong><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; font-family: \'Times New Roman\',\'serif\';\">Il est attrist&eacute; &laquo;&nbsp;</span></strong><span lang=\"FR\" style=\"mso-bidi-font-size: 10.0pt; font-family: \'Arial\',\'sans-serif\';\">N\'attristez pas le Saint-Esprit de Dieu, par lequel vous avez &eacute;t&eacute; scell&eacute;s pour le jour de la r&eacute;demption.&nbsp;&raquo; (<strong style=\"mso-bidi-font-weight: normal;\">Eph&eacute;siens 4&nbsp;:30</strong>)</span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify; line-height: normal; mso-layout-grid-align: none; text-autospace: none;\"><strong><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; font-family: \'Times New Roman\',\'serif\';\">L&rsquo;association du Saint-Esprit avec le p&egrave;re et le Fils d&eacute;montre qu&rsquo;Il est aussi une personnalit&eacute; comme les deux&nbsp;: </span></strong><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; font-family: \'Times New Roman\',\'serif\'; mso-bidi-font-weight: bold;\">Ils sont associ&eacute;s dans la formule baptismale (<strong>Matthieu 28&nbsp;:19</strong>), dans la b&eacute;n&eacute;diction Apostolique (<strong>2 Cor 13&nbsp;:13</strong>) et dans la distribution des dons <strong>(1 Cor12&nbsp;:4-6)</strong></span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><strong><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">La Mission du Saint-Esprit dans le plan du salut de l&rsquo;homme</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\'; mso-bidi-font-weight: bold;\">&nbsp;</span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify; text-indent: -9.0pt; mso-list: l0 level1 lfo1; tab-stops: 22.5pt; margin: 0cm 0cm .0001pt 4.5pt;\"><!-- [if !supportLists]--><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\';\"><span style=\"mso-list: Ignore;\">1.</span></span><!--[endif]--><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">Le Saint-Esprit convint du p&eacute;ch&eacute; de la justice, et du jugement &laquo;&nbsp;Et quand il sera venu, il convaincra le monde en ce qui concerne le p&eacute;ch&eacute;, la justice, et le jugement :&nbsp;&raquo; (<strong style=\"mso-bidi-font-weight: normal;\">Jean 16&nbsp;:8</strong>)</span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify; text-indent: -9.0pt; mso-list: l0 level1 lfo1; tab-stops: 22.5pt; margin: 0cm 0cm .0001pt 4.5pt;\"><!-- [if !supportLists]--><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\';\"><span style=\"mso-list: Ignore;\">2.</span></span><!--[endif]--><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">Le Saint-Esprit convint d&rsquo;accepter J&eacute;sus-Christ et son &oelig;uvre pour notre salut: &laquo;&nbsp;C\'est pourquoi je vous d&eacute;clare que nul, s\'il parle par l\'Esprit de Dieu, ne dit: J&eacute;sus est anath&egrave;me! et que nul ne peut dire: J&eacute;sus est le Seigneur! si ce n\'est par le Saint-Esprit.&nbsp;&raquo; (<strong style=\"mso-bidi-font-weight: normal;\">1 cor 12&nbsp;:3</strong>)</span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify; text-indent: -9.0pt; mso-list: l0 level1 lfo1; tab-stops: 22.5pt; margin: 0cm 0cm .0001pt 4.5pt;\"><!-- [if !supportLists]--><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\';\"><span style=\"mso-list: Ignore;\">3.</span></span><!--[endif]--><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">Le Saint-Esprit console et interc&egrave;de pour les croyants (<strong>Jean 14:16</strong>; <strong>Romains 8:26</strong>)</span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify; text-indent: -9.0pt; mso-list: l0 level1 lfo1; tab-stops: 22.5pt; margin: 0cm 0cm .0001pt 4.5pt;\"><!-- [if !supportLists]--><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\';\"><span style=\"mso-list: Ignore;\">4.</span></span><!--[endif]--><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">Le Saint-Esprit enseigne la v&eacute;rit&eacute; sur Christ aux croyants (<strong>Jean 14 :26; 16:13</strong>);</span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify; text-indent: -9.0pt; mso-list: l0 level1 lfo1; tab-stops: 22.5pt; margin: 0cm 0cm .0001pt 4.5pt;\"><!-- [if !supportLists]--><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\';\"><span style=\"mso-list: Ignore;\">5.</span></span></strong><!--[endif]--><span lang=\"FR\" style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">Il avait inspir&eacute; les &eacute;crivains de la Bible <strong style=\"mso-bidi-font-weight: normal;\">2 Samuel 23 :2</strong></span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify; tab-stops: 22.5pt; margin: 0cm 0cm .0001pt 4.5pt;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">&nbsp;</span></p>', 5, '2025-10-23 15:04:53'),
(12, 1, 'LEÇON N° 6 : LA CREATION', '<p class=\"MsoNormal\" style=\"text-align: center;\" align=\"center\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"mso-bidi-font-size: 10.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">LE&Ccedil;ON N&deg; 6 : LA CREATION</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Un de grands probl&egrave;mes auquel l&rsquo;&eacute;glise chr&eacute;tienne est confront&eacute;e aujourd&rsquo;hui est en rapport avec le r&eacute;cit biblique de la cr&eacute;ation rapport&eacute; dans le livre de Gen&egrave;se. Depuis que Charles Darwin a publi&eacute; son livre intitul&eacute; &laquo;&nbsp;L&rsquo;Origine des Esp&egrave;ces&nbsp;&raquo; en 1859, l&rsquo;id&eacute;e selon laquelle le monde a &eacute;t&eacute; cr&eacute;&eacute; par Dieu en six jours litt&eacute;raux fut d&eacute;fi&eacute;e par la th&eacute;orie de l&rsquo;&eacute;volution.</span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Toute h&eacute;r&eacute;sie que Satan a introduite dans ce monde quant &agrave; la cr&eacute;ation constitue en fin de compte une attaque contre l&rsquo;&eacute;vangile. Cela inclut la th&eacute;orie de l&rsquo;&eacute;volution qui renie la puissance cr&eacute;atrice de Dieu. Ainsi, au cours de cette &eacute;tude, nous examinerons ce que la Bible dit au sujet de la cr&eacute;ation de ce monde, particuli&egrave;rement de l&rsquo;homme, &agrave; la lumi&egrave;re de l&rsquo;&eacute;vangile de notre Seigneur J&eacute;sus-Christ. </span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify; margin: 12.0pt 0cm .0001pt 0cm;\"><strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Cr&eacute;ation en 6 Jours Litt&eacute;raux.</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify; line-height: 150%;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Certains croient que, comme pour Dieu un jour est comme mille ans et mille ans comme un jour (<strong>2 Pierre 3:8</strong>), alors les 6 jours de cr&eacute;ation ne sont pas des jours de 24 heures chacun, mais plut&ocirc;t des jours symboliques dont chacun vaut une longue p&eacute;riode de temps. Une petite question de r&eacute;flexion, selon l&rsquo;id&eacute;e ci haut si les 6 jours de la cr&eacute;ation sont symboliques d&rsquo;o&ugrave; sont &ndash; ils- venus les 6 jours litt&eacute;raux de 24 heures chacun que nous avons aujourd&rsquo;hui&nbsp;? Ceci prouve que cette id&eacute;e est erron&eacute;e car, (1) l&rsquo;expression &laquo;il y eut un soir et il y eut un matin &raquo; (<strong style=\"mso-bidi-font-weight: normal;\">Gen&egrave;se 1 :5,8,13,19,23,31 ; cf. L&eacute;vitique 23:32; </strong></span></p>\r\n<p class=\"MsoNormal\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\">&nbsp;</span></strong></p>\r\n<p class=\"Default\" style=\"text-align: justify;\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Deut&eacute;ronome 16 :6</span></strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">) indique un jour de 24 heures; (2) le mot h&eacute;breu <em>yom </em>(jour) accompagn&eacute; d&rsquo;un adjectif num&eacute;ral ordinal d&eacute;signe un jour de 24 h (<strong style=\"mso-bidi-font-weight: normal;\">Gen&egrave;se 7:11</strong>; <strong style=\"mso-bidi-font-weight: normal;\">Exode 16:1; L&eacute;vitique 23:34; Ez&eacute;chiel 45:21; Agg&eacute;e 1:1; Zacharie 1:7);</strong> (3) Dieu ne pouvait pas exiger &agrave; l&rsquo; homme d&rsquo;observer le 7&egrave;me jour comme Sabbat si les 6 jours de cr&eacute;ation n&rsquo;&eacute;taient pas des jours litt&eacute;raux de 24 h chacun. Dieu avait cr&eacute;&eacute; des liminaires pour s&eacute;parer la journ&eacute;e et la nuit,12 h pour la journ&eacute;e et 12h pour la nuit (<strong style=\"mso-bidi-font-weight: normal;\">Gen&egrave;se 1&nbsp;:14&nbsp;;Jean 11&nbsp;:9</strong>)</span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: center;\" align=\"center\"><strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">But de la Cr&eacute;ation.</span></strong></p>\r\n<p class=\"Default\" style=\"text-align: justify; line-height: 115%;\"><span lang=\"FR\" style=\"font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\'; color: windowtext;\">Le premier but de la cr&eacute;ation est de r&eacute;v&eacute;ler la <strong>gloire </strong>de Dieu. <strong>Psaumes 19:1-2</strong>: &laquo;Les cieux racontent la gloire de Dieu, Et l\'&eacute;tendue manifeste l\'&oelig;uvre de ses mains. Le jour en instruit un autre jour, La nuit en donne connaissance &agrave; une autre nuit.&raquo; <strong>Romains 1:20</strong>: &laquo;Les perfections invisibles de Dieu, sa puissance &eacute;ternelle et sa divinit&eacute;, se voient comme &agrave; l\'&oelig;il, depuis la cr&eacute;ation du monde, quand on les consid&egrave;re dans ses ouvrages&raquo; (cf. <strong>Psaumes 104</strong>). Un autre but est de <strong>peupler le monde</strong>. <strong>Gen&egrave;se 1:28</strong>: &laquo;Dieu les b&eacute;nit, et Dieu leur dit: Soyez f&eacute;conds, multipliez, <strong>remplissez la terre</strong>, et l\'assujettissez; et dominez sur les poissons de la mer, sur les oiseaux du ciel, et sur tout animal</span><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\"> </span><span lang=\"FR\" style=\"font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\'; color: windowtext;\">qui se meut sur la terre.&raquo; <strong>Esa&iuml;e 45:18</strong>: &laquo;Car ainsi parle l\'&Eacute;ternel, Le cr&eacute;ateur des cieux, le seul Dieu, Qui a form&eacute; la terre, qui l\'a faite et qui l\'a affermie, Qui l\'a cr&eacute;&eacute;e pour qu\'elle ne f&ucirc;t pas d&eacute;serte, Qui l\'a form&eacute;e pour qu\'elle f&ucirc;t habit&eacute;e : Je suis l\'&Eacute;ternel, et il n\'y en a point d\'autre.&raquo;</span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify; margin: 0cm 4.55pt .0001pt 4.5pt;\"><span lang=\"FR\" style=\"font-size: 10.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">&nbsp;</span></p>\r\n<p class=\"Default\" style=\"text-align: justify; line-height: 150%;\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-size: 11.0pt; line-height: 150%; font-family: \'Times New Roman\',\'serif\'; color: windowtext;\">Christ, l&rsquo;Agent Principal de la cr&eacute;ation.</span></strong></p>\r\n<p class=\"Default\" style=\"text-align: justify; line-height: 150%;\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"mso-bidi-font-size: 10.0pt; line-height: 150%; font-family: \'Times New Roman\',\'serif\';\">Jean</span></strong><strong><span lang=\"FR\" style=\"font-size: 11.0pt; line-height: 150%; font-family: \'Times New Roman\',\'serif\'; color: windowtext;\"> 1:1-3</span></strong><span lang=\"FR\" style=\"font-size: 11.0pt; line-height: 150%; font-family: \'Times New Roman\',\'serif\'; color: windowtext;\">: &laquo;Au commencement &eacute;tait la Parole, et la Parole &eacute;tait avec Dieu, et la Parole &eacute;tait Dieu. Elle &eacute;tait au commencement avec Dieu. <strong>Toutes choses ont &eacute;t&eacute; faites par elle</strong>, et rien de ce qui a &eacute;t&eacute; fait n \'a &eacute;t&eacute; fait sans elle.&raquo;</span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify; line-height: 150%;\"><strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Colossiens 1 :16</span></strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">: &laquo;En lui [Christ] ont &eacute;t&eacute; cr&eacute;&eacute;es toutes les choses qui sont dans les cieux et sur la terre, les visibles et les invisibles, tr&ocirc;nes, dignit&eacute;s, dominations, autorit&eacute;s. <strong>Tout a &eacute;t&eacute; cr&eacute;&eacute; par lui et pour lui</strong>.&raquo; La Trinit&eacute; &eacute;tait pr&eacute;sente &agrave; la cr&eacute;ation (<strong>Gen&egrave;se 1:2,26</strong>), mais c&rsquo;est Christ l&rsquo;agent principal de la cr&eacute;ation. Sachant maintenant que Dieu vous a cr&eacute;&eacute; pour que vous refl&eacute;tiez sa gloire, la refl&eacute;tez-vous ? Sinon, pourquoi ? Voudriez-vous ouvrir votre c&oelig;ur &agrave; J&eacute;sus-Christ pour qu&rsquo;il vous transforme par son Esprit afin que vous refl&eacute;tiez la gloire de Dieu votre Cr&eacute;ateur ?</span></p>\r\n<p class=\"MsoNormal\"><span lang=\"FR\">&nbsp;</span></p>', 6, '2025-10-23 15:07:25');
INSERT INTO `lecons` (`id`, `categorie_id`, `titre`, `contenu`, `ordre`, `date_creation`) VALUES
(13, 1, 'LEÇON N°7 : L’ETAT DES MORTS', '<p class=\"MsoNormal\" style=\"text-align: center;\" align=\"center\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"mso-bidi-font-size: 10.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">LE&Ccedil;ON N&deg;7 : L&rsquo;ETAT DES MORTS</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify; tab-stops: 87.75pt; margin: 0cm 2.4pt .0001pt 0cm;\"><span lang=\"FR\" style=\"font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">Une des questions qui pr&eacute;occupent au premier plan l&rsquo;esprit des gens est&nbsp;: Que se passe-t-il quand quelqu&rsquo;un meurt&nbsp;? Cela est particuli&egrave;rement vrai lorsque nous avons perdu un &ecirc;tre cher. Selon la Bible, tout homme a<span style=\"mso-spacerun: yes;\">&nbsp; </span>peur de la mort (voir H&eacute;breux 2&nbsp;: 15). </span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify; tab-stops: 87.75pt; margin: 0cm 2.4pt .0001pt 0cm;\"><span lang=\"FR\" style=\"font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">La raison principale &agrave; cela est que<span style=\"mso-spacerun: yes;\">&nbsp; </span>certaines personnes ne<span style=\"mso-spacerun: yes;\">&nbsp; </span>connaissent<span style=\"mso-spacerun: yes;\">&nbsp; </span>pas ce qu&rsquo;est leurs destin&eacute;e ou ce qui leurs arrivera lorsqu&rsquo;ils mourront. La croyance populaire dit que l&rsquo;&acirc;me du<span style=\"mso-spacerun: yes;\">&nbsp; </span>juste va jouir de la f&eacute;licit&eacute; du ciel tandis que celle de m&eacute;chant va en enfer pour br&ucirc;ler &eacute;ternellement. Plusieurs religions pa&iuml;ennes et particuli&egrave;rement la mythologie grecque enseignent que l&rsquo;&acirc;me de l&rsquo;homme est immortelle. Malheureusement, cette id&eacute;e de l&rsquo;immortalit&eacute; de l&rsquo;&acirc;me a &eacute;t&eacute; emprunt&eacute;e des Grecs par les P&egrave;res de l&rsquo;&eacute;glise primitive, et introduite dans le christianisme. Cependant, ne soyez pas surpris d&rsquo;apprendre que cette id&eacute;e ne se trouve nulle part dans la Bible. Qu&rsquo;est-ce que la Bible enseigne donc au sujet de l&rsquo;&acirc;me et de l&rsquo;&eacute;tat de l&rsquo;homme apr&egrave;s la mort&nbsp;? Trois points nous serviront dans cette &eacute;tude pour nous permettre une bonne compr&eacute;hension.</span></p>\r\n<p class=\"MsoListParagraph\" style=\"margin-right: -35.45pt; mso-add-space: auto; text-align: justify; text-indent: -18.0pt; mso-list: l0 level1 lfo1; tab-stops: 87.75pt;\"><!-- [if !supportLists]--><strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\';\"><span style=\"mso-list: Ignore;\">1.<span style=\"font: 7.0pt \'Times New Roman\';\">&nbsp;&nbsp;&nbsp;&nbsp; </span></span></span></strong><!--[endif]--><strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">De quoi l&rsquo;homme est-il constitu&eacute;.</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-right: 2.4pt; text-align: justify; tab-stops: 87.75pt;\"><strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Gen&egrave;se 2:7</span></strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">: &laquo;L\'&Eacute;ternel Dieu forma l\'homme de la <strong>poussi&egrave;re </strong>de la terre, il souffla dans ses narines un <strong>souffle de vie </strong>et l\'homme devint un &ecirc;tre vivant.&raquo;<span style=\"mso-spacerun: yes;\">&nbsp; </span>L&rsquo;&ecirc;tre vivant = la combinaison</span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify; tab-stops: 87.75pt; margin: 0cm -5.0pt .0001pt 0cm;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">de ces deux &eacute;l&eacute;ments.<strong> </strong>La Bible <em>Darby </em>traduit Gen&egrave;se 2:7 de la mani&egrave;re suivante<span style=\"mso-spacerun: yes;\">&nbsp; </span>&laquo;Et l\'&Eacute;ternel Dieu forma l&rsquo; homme, poussi&egrave;re du sol, et souffla dans ses narines une respiration de vie, et l&rsquo; homme devint une <strong>&acirc;me vivante</strong>.&raquo; </span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify; text-indent: -22.5pt; tab-stops: 87.75pt; margin: 0cm -.5pt 10.0pt 18.0pt;\"><strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">2. Que c&rsquo;est que l&rsquo;Ame&nbsp;? est-elle Immortelle&nbsp;?</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify; tab-stops: 87.75pt; margin: 0cm -.5pt .0001pt 0cm;\"><span lang=\"FR\" style=\"font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">Job 27&nbsp;:3 &laquo;&nbsp;Aussi longtemps que j\'aurai ma respiration, Et que le souffle de Dieu sera dans mes narines&nbsp;&raquo; l&rsquo;&acirc;me ou souffle de vie c&rsquo;est cette vapeur<span style=\"mso-spacerun: yes;\">&nbsp; </span>que nous respirons. Le souffle de Dieu est dans les narines. Matthieu 10:28: &laquo;Ne craignez pas ceux qui tuent le corps et qui ne peuvent tuer l\'&acirc;me; craignez plut&ocirc;t celui qui peut faire p&eacute;rir l\'&acirc;me et le corps dans la g&eacute;henne.&raquo; Donc l&rsquo;&acirc;me peut &ecirc;tre d&eacute;truite et peut p&eacute;rir.</span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: center; tab-stops: 87.75pt; margin: 0cm -.5pt .0001pt 0cm;\" align=\"center\"><strong><span lang=\"FR\" style=\"font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">3. L&rsquo;&acirc;me morte peut-elle communiquer avec les vivants ?</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-right: -.5pt; text-align: justify; tab-stops: 87.75pt;\"><strong><span lang=\"FR\" style=\"font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">Eccl&eacute;siastes 9 :5-6</span></strong><span lang=\"FR\" style=\"font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">: &laquo;Les vivants, en effet, savent qu\'ils mourront; mais <strong>les morts ne savent rien, et il n\'y a pour eux plus de salaire, puisque leur m&eacute;moire est oubli&eacute;e. Et leur amour, et leur haine, et leur envie, ont d&eacute;j&agrave; p&eacute;ri ; et ils n\'auront plus jamais aucune part &agrave; tout ce qui se fait sous le soleil</strong>. &raquo; <strong>Job 7 :6-10</strong>: &laquo;Mes jours sont plus rapides que la navette du tisserand, Ils s\'&eacute;vanouissent: plus d\'esp&eacute;rance! Souviens-toi que ma vie est un souffle ! Mes yeux ne reverront pas le bonheur. L\'&oelig;il qui me regarde ne me regardera plus ; Ton &oelig;il me cherchera, et je ne serai plus. <strong>Comme la nu&eacute;e se dissipe et s\'en va, Celui qui&nbsp;</strong></span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify; line-height: normal; tab-stops: 0cm; mso-layout-grid-align: none; text-autospace: none;\"><strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">descend au s&eacute;jour des morts ne remontera pas; Il ne reviendra plus dans sa maison, Et le lieu qu\'il habitait ne le conna&icirc;tra plus</span></strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">.&raquo; </span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify; line-height: 150%; tab-stops: 0cm; mso-layout-grid-align: none; text-autospace: none;\"><strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">Job 14:12</span></strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">: &laquo;Ainsi l\'homme se couche et ne se rel&egrave;vera plus, Il ne se r&eacute;veillera pas tant que les cieux subsisteront, Il ne sortira pas de son sommeil.&raquo; Donc les morts sont dans l&rsquo;inconscience, ils sont dans un sommeil. Ils restent dans les tombes jusqu&rsquo;&agrave; leur r&eacute;surrection. <strong style=\"mso-bidi-font-weight: normal;\">Jean 5&nbsp;:28&nbsp;; Daniel 12&nbsp;:2</strong> </span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify; line-height: normal; tab-stops: 0cm; mso-layout-grid-align: none; text-autospace: none;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">&nbsp;</span></p>', 7, '2025-10-23 15:09:51'),
(14, 1, 'LEÇON 8: l’ORIGINE DU MAL', '<p class=\"MsoNormal\" style=\"text-align: center;\" align=\"center\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-size: 10.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">LE&Ccedil;ON </span></strong><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"mso-bidi-font-size: 10.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">N&deg; </span></strong><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"font-size: 10.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">8&nbsp;: L&rsquo;ORIGINE DU MAL</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><span lang=\"FR\" style=\"font-size: 10.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">Lorsqu&rsquo;elle sortit des mains du Cr&eacute;ateur, la terre &eacute;tait d&rsquo;une &eacute;clatante beaut&eacute;. Sa surface &eacute;tait ondul&eacute;e de montagnes et de collines, parsem&eacute;e de lacs d&eacute;licieux et arros&eacute;e de superbes fleuves.il n&rsquo;y avait ni souffrance ni peine. D&rsquo;o&ugrave; sont venus ce mal et toute cette souffrance&nbsp;?</span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: center;\" align=\"center\"><strong><span lang=\"FR\" style=\"font-size: 10.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">L&rsquo;origine du p&eacute;ch&eacute;</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><span lang=\"FR\" style=\"font-size: 10.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">La Bible se sert des rois de Tyr et de Babylone comme figures de Lucifer pour nous expliquer l&rsquo;origine du p&eacute;ch&eacute;. </span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><strong><span lang=\"FR\" style=\"font-size: 10.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">Ez&eacute;chiel 28 :14-18</span></strong><span lang=\"FR\" style=\"font-size: 10.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\"> : &laquo; Tu &eacute;tais un ch&eacute;rubin protecteur, aux ailes d&eacute;ploy&eacute;es ; Je t\'avais plac&eacute; et tu &eacute;tais sur la sainte montagne de Dieu ; Tu marchais au milieu des pierres &eacute;tincelantes. Tu as &eacute;t&eacute; int&egrave;gre dans tes voies, Depuis le jour o&ugrave; tu fus cr&eacute;&eacute; Jusqu\'&agrave; celui o&ugrave; l\'iniquit&eacute; a &eacute;t&eacute; trouv&eacute;e chez toi. Par la grandeur de ton commerce, tu as &eacute;t&eacute; rempli de violence, et tu as p&eacute;ch&eacute; ; Je te pr&eacute;cipite de la montagne de Dieu, Et je te fais dispara&icirc;tre, ch&eacute;rubin protecteur, du milieu des pierres &eacute;tincelantes. Ton c&oelig;ur s\'est &eacute;lev&eacute; &agrave; cause de ta beaut&eacute;, tu as corrompu ta sagesse par ton &eacute;clat. Je te jette par terre, Je te livre en spectacle aux rois. Par la multitude de tes iniquit&eacute;s, par l\'injustice de ton commerce, tu as profan&eacute; tes sanctuaires ; Je fais sortir du milieu de toi un feu qui te d&eacute;vore, Je te r&eacute;duis en cendre sur la terre, Aux yeux de tous ceux qui te regardent &raquo; </span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><strong><span lang=\"FR\" style=\"font-size: 10.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">Esa&iuml;e 14 :12-15</span></strong><span lang=\"FR\" style=\"font-size: 10.0pt; mso-bidi-font-size: 11.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\"> : &laquo; Te voil&agrave; tomb&eacute; du ciel, Astre brillant, fils de l&rsquo;aurore ! Tu es abattu &agrave; terre, Toi, le vainqueur des nations ! Tu disais en ton c&oelig;ur : Je monterai au ciel, J\'&eacute;l&egrave;verai mon tr&ocirc;ne au-dessus des &eacute;toiles de Dieu ; Je m\'assi&eacute;rai sur la montagne de l\'assembl&eacute;e, &Agrave; l\'extr&eacute;mit&eacute; du septentrion ; Je monterai sur le sommet des nues, Je serai semblable au Tr&egrave;s-Haut. Mais tu as &eacute;t&eacute; pr&eacute;cipit&eacute; dans le s&eacute;jour des morts, Dans les profondeurs de la fosse. &raquo; L&rsquo;orgueil est n&eacute; dans le c&oelig;ur de Lucifer et il a commenc&eacute; &agrave; convoiter la place m&ecirc;me de Dieu et il finit par &ecirc;tre Satan ou Adversaire.</span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><strong style=\"mso-bidi-font-weight: normal;\"><span lang=\"FR\" style=\"mso-bidi-font-size: 10.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\';\">&nbsp;</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><span style=\"font-family: \'Times New Roman\',\'serif\';\"><span style=\"mso-spacerun: yes;\">&nbsp;</span><strong><span lang=\"FR\">Apocalypse 12 :7-9</span></strong><span lang=\"FR\"> : &laquo; Et il y eut guerre dans le ciel. Michel et ses anges combattirent contre le dragon. Et le dragon et ses anges combattirent, mais ils ne furent pas les plus forts, et leur place ne fut plus trouv&eacute;e dans le ciel. Et il fut pr&eacute;cipit&eacute;, le grand dragon, le serpent ancien, appel&eacute; le diable et Satan, celui qui s&eacute;duit toute la terre, il fut pr&eacute;cipit&eacute; sur la terre, et ses anges furent pr&eacute;cipit&eacute;s avec lui. &raquo; </span></span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\"><span style=\"mso-spacerun: yes;\">&nbsp;</span>Le P&eacute;ch&eacute; sur la Terre<span style=\"mso-spacerun: yes;\">&nbsp; </span></span></strong></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\">La semence du p&eacute;ch&eacute; est entr&eacute;e sur la plan&egrave;te Terre <strong style=\"mso-bidi-font-weight: normal;\"><em style=\"mso-bidi-font-style: normal;\">lorsque Satan a incit&eacute; Adam et Eve &agrave; d&eacute;sob&eacute;ir &agrave; Dieu en mangeant le fruit d&eacute;fendu en</em></strong> <strong style=\"mso-bidi-font-weight: normal;\">Gen&egrave;se 2 :17</strong>. Voici la mani&egrave;re dont Satan a s&eacute;duit Eve &agrave; travers un serpent. <strong>Gen&egrave;se 3 :1-6</strong> : &laquo; Le serpent &eacute;tait le plus rus&eacute; de tous les animaux des champs, que l\'&Eacute;ternel Dieu avait faits. Il dit &agrave; la femme : Dieu a-t -il r&eacute;ellement dit : Vous ne mangerez pas de tous les arbres du jardin ? La femme r&eacute;pondit au serpent : Nous mangeons du fruit des arbres du jardin. Mais quant au fruit de l\'arbre qui est au milieu du jardin, Dieu a dit : Vous n\'en mangerez point et vous n\'y toucherez point, de peur que vous ne mouriez. Alors le serpent dit &agrave; la femme : Vous ne mourrez point ; mais Dieu sait que, le jour o&ugrave; vous en mangerez, vos yeux s\'ouvriront, et que vous serez comme des dieux, connaissant le bien et le mal. La femme vit que l\'arbre &eacute;tait bon &agrave; manger et agr&eacute;able &agrave; la vue, et qu\'il &eacute;tait pr&eacute;cieux pour ouvrir l&rsquo;intelligence ; elle prit de son fruit, et en mangea ; elle en donna aussi &agrave; son mari, qui &eacute;tait aupr&egrave;s d\'elle, et il en mangea. &raquo; </span></p>\r\n<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: justify;\"><strong><span lang=\"FR\" style=\"font-family: \'Times New Roman\',\'serif\';\"><span style=\"mso-spacerun: yes;\">&nbsp;&nbsp;</span></span></strong></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify; tab-stops: 22.5pt; margin: 0cm 0cm .0001pt 4.5pt;\"><strong><span lang=\"FR\" style=\"font-size: 10.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: FR;\">Cons&eacute;quences de l&rsquo;Entr&eacute;e du P&eacute;ch&eacute; sur la Terre</span></strong></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify; tab-stops: 22.5pt; margin: 0cm 0cm .0001pt 4.5pt;\"><span lang=\"FR\" style=\"font-size: 10.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: FR;\">La <strong>premi&egrave;re cons&eacute;quence </strong>&eacute;tait la <strong style=\"mso-bidi-font-weight: normal;\"><em style=\"mso-bidi-font-style: normal;\">nudit&eacute;</em></strong> <strong style=\"mso-bidi-font-weight: normal;\"><em style=\"mso-bidi-font-style: normal;\">d&rsquo;Adam et Eve et leur fuite loin de Dieu</em></strong> : <strong>Gen&egrave;se 3 :8-10</strong> : &laquo; Alors ils entendirent la voix de l\'&Eacute;ternel Dieu, qui parcourait le jardin vers le soir, et l\'homme et sa femme se cach&egrave;rent loin de la face de l\'&Eacute;ternel Dieu, au milieu des arbres du jardin. Mais l\'&Eacute;ternel Dieu appela l\'homme, et lui dit : O&ugrave; es-tu ? Il r&eacute;pondit : J\'ai entendu ta voix dans le jardin, et j\'ai eu peur, parce que je suis nu, et je me suis cach&eacute;. &raquo; </span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify; tab-stops: 22.5pt; margin: 0cm 0cm .0001pt 4.5pt;\"><span lang=\"FR\" style=\"font-size: 10.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: FR;\">La <strong>deuxi&egrave;me cons&eacute;quence </strong>&eacute;tait <strong style=\"mso-bidi-font-weight: normal;\"><em style=\"mso-bidi-font-style: normal;\">la dislocation des liens entre Adam et Eve, Adam se plaint contre Eve</em></strong> : <strong>Gen&egrave;se 3 :9-12</strong> : &laquo; Mais l\'&Eacute;ternel Dieu appela l\'homme, et lui dit : O&ugrave; es-tu ? Il r&eacute;pondit : J\'ai entendu ta voix dans le jardin, et j\'ai eu peur, parce que je suis nu, et je me suis cach&eacute;. Et l\'&Eacute;ternel Dieu dit : Qui t\'a appris que tu es nu ? Est-ce que tu as mang&eacute; de l\'arbre dont je t\'avais d&eacute;fendu de manger ? L\'homme r&eacute;pondit : La femme que tu as mise aupr&egrave;s de moi m\'a donn&eacute; de l\'arbre, et j\'en ai mang&eacute;. &raquo; </span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify; tab-stops: 22.5pt; margin: 0cm 0cm .0001pt 4.5pt;\"><span lang=\"FR\" style=\"font-size: 10.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: FR;\">La <strong>troisi&egrave;me cons&eacute;quence </strong>&eacute;tait <strong style=\"mso-bidi-font-weight: normal;\"><em style=\"mso-bidi-font-style: normal;\">la mal&eacute;diction suivie de la sentence de mort</em></strong>, <strong>Gen&egrave;se 3 :16-19</strong> : &laquo; Il [l&rsquo;Eternel] dit &agrave; la femme : J\'augmenterai la souffrance de tes grossesses, tu enfanteras avec douleur, et tes d&eacute;sirs se porteront vers ton mari, mais il dominera sur toi. Il dit &agrave; l&rsquo;homme : Puisque tu as &eacute;cout&eacute; la voix de ta femme, et que tu as mang&eacute; de l\'arbre au sujet duquel je t\'avais donn&eacute; cet ordre : Tu n\'en mangeras point ! le sol sera maudit &agrave; cause de toi. C\'est &agrave; force de peine que tu en tireras ta nourriture tous les jours de ta vie, il te produira des &eacute;pines et des ronces, et tu mangeras de l\'herbe des champs. C\'est &agrave; la sueur de ton visage que tu mangeras du pain, jusqu\'&agrave; ce que tu retournes dans la terre, d\'o&ugrave; tu as &eacute;t&eacute; pris ; car tu es poussi&egrave;re, et tu retourneras dans la poussi&egrave;re. &raquo;</span></p>\r\n<p class=\"MsoNormal\" style=\"text-align: justify; tab-stops: 22.5pt; margin: 0cm 0cm .0001pt 4.5pt;\"><span lang=\"FR\" style=\"font-size: 10.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: FR;\">&nbsp;</span></p>', 8, '2025-10-23 15:12:14'),
(15, 1, 'LEÇON 9 : LA VIE, la mort et  La résurrection DU CHRIST', '<p class=\"MsoNormal\" style=\"margin-bottom: .0001pt; text-align: center;\" align=\"center\"><!-- [if gte vml 1]><v:rect id=\"Zone_x0020_de_x0020_texte_x0020_3\"\r\n o:spid=\"_x0000_s1027\" style=\'position:absolute;left:0;text-align:left;\r\n margin-left:96.5pt;margin-top:-23.5pt;width:27pt;height:20.5pt;z-index:6;\r\n visibility:visible;mso-wrap-style:square;mso-width-percent:0;\r\n mso-height-percent:0;mso-wrap-distance-left:0;mso-wrap-distance-top:0;\r\n mso-wrap-distance-right:0;mso-wrap-distance-bottom:0;\r\n mso-position-horizontal:absolute;mso-position-horizontal-relative:text;\r\n mso-position-vertical:absolute;mso-position-vertical-relative:text;\r\n mso-width-percent:0;mso-height-percent:0;mso-width-relative:margin;\r\n mso-height-relative:margin;v-text-anchor:top\' o:gfxdata=\"UEsDBBQABgAIAAAAIQC75UiUBQEAAB4CAAATAAAAW0NvbnRlbnRfVHlwZXNdLnhtbKSRvU7DMBSF\r\ndyTewfKKEqcMCKEmHfgZgaE8wMW+SSwc27JvS/v23KTJgkoXFsu+P+c7Ol5vDoMTe0zZBl/LVVlJ\r\ngV4HY31Xy4/tS3EvRSbwBlzwWMsjZrlprq/W22PELHjb51r2RPFBqax7HCCXIaLnThvSAMTP1KkI\r\n+gs6VLdVdad08ISeCho1ZLN+whZ2jsTzgcsnJwldluLxNDiyagkxOquB2Knae/OLUsyEkjenmdzb\r\nmG/YhlRnCWPnb8C898bRJGtQvEOiVxjYhtLOxs8AySiT4JuDystlVV4WPeM6tK3VaILeDZxIOSsu\r\nti/jidNGNZ3/J08yC1dNv9v8AAAA//8DAFBLAwQUAAYACAAAACEArTA/8cEAAAAyAQAACwAAAF9y\r\nZWxzLy5yZWxzhI/NCsIwEITvgu8Q9m7TehCRpr2I4FX0AdZk2wbbJGTj39ubi6AgeJtl2G9m6vYx\r\njeJGka13CqqiBEFOe2Ndr+B03C3WIDihMzh6RwqexNA281l9oBFTfuLBBhaZ4ljBkFLYSMl6oAm5\r\n8IFcdjofJ0z5jL0MqC/Yk1yW5UrGTwY0X0yxNwri3lQgjs+Qk/+zfddZTVuvrxO59CNCmoj3vCwj\r\nMfaUFOjRhrPHaN4Wv0VV5OYgm1p+LW1eAAAA//8DAFBLAwQUAAYACAAAACEAMzr6DI4CAAAoBgAA\r\nHwAAAGNsaXBib2FyZC9kcmF3aW5ncy9kcmF3aW5nMS54bWy8VE1v2zAMvQ/YfxB0b+24SfOBOkXX\r\nLcWAogvqFgN2Y2Q5NiZLmqS4Tn/9KMv5WLf1sA3LwTFF8vnxkdTFZVsL0nBjKyVTOjiNKeGSqbyS\r\n65Q+PixOJpRYBzIHoSRP6ZZbejl/++YCZmsDuqwYQQRpZ5DS0jk9iyLLSl6DPVWaS/QVytTg0DTr\r\nKDfwhMi1iJI4Po9qqCSdH6DegwOyMdUfQAnFvvL8GmQDFiEFmx2f9BwF+3tkmMnmxuhML41nzu6a\r\npSFVnlJUTkK