(151, 21, '4.	Pourquoi le Premier et le dernier jour de la fête des Pains sans Levain sont –ils été appelés des sabbats ? \r\nNombres 28 :18,25', 4),
(152, 21, '5.	Qu’est-ce qui est Pâque dans le christianisme aujourd’hui ? 1 Corinthiens 5 :7', 5),
(153, 21, '6.	Que symbolisait la gerbe (prémices) qu’on agitait devant le sacrificateur le lendemain du sabbat (Lévitiques 23 :6-12) dans le christianisme aujourd’hui ? \r\n1 Corinthiens 15 :20-23', 6),
(154, 21, '7.	Pendant la fête des semaines où on recommandait au juif de ne pas faire aucune œuvre servile comment était appelé ces assemblées ? Nombre 28 :26', 7),
(155, 21, 'A quelle date (mois et jour) avait-il eu lieu la fête des tabernacles?  Lévitique 23 :34.', 8),
(156, 21, 'Quelles sont les deux recommandations exigées aux israélites pendant le Jour des Expiations? Nombres 29 :7', 9),
(157, 21, 'Pourquoi ces saintes convocations sont –elles été appelées des sabbats ? Nombres 28 :25 ,26 ; 29 : 1,712', 10),
(158, 22, 'Quel est le premier jour dont on fait mention en Lévitique 23 :33-35?', 1),
(159, 22, 'La fête de pains sans levains était célébrée pendant combien de jour ? Nombres 28 :16-18', 2),
(160, 22, '.La fête des tabernacles était célébrée pendant combien de jour lieu ? Lévitique 23 :33-35 ?', 3),
(161, 22, 'Qu’est-ce qu’on demandait   aux enfants d’Israël de faire pendant le premier et dernier jour de pains sans levain ? Nombres 28 :18,25', 4),
(162, 22, '.Qu’est-ce qu’on demandait   aux enfants d’Israël de faire pendant le premier jour de la fête de tabernacle ? Lévitique 23 :33-35 ?', 5),
(163, 22, 'Pourquoi les disciples c’étaient réuni le soir du premier de la semaine ou les portes du lieu où ils se trouvaient étant fermées ? Jean 20 :19', 6),
(164, 22, 'Pourquoi Paul avait prolongé son discours jusqu\'à minuit ? Actes 20 :7,9-12.', 7),
(165, 22, 'selon Genèse 1 :5, 8, 13, le discours de Paul a commencé quel jour pour se prolonger son jusqu’à minuit ? Actes 20 :7,9-12.', 8),
(166, 22, 'Où est ce que Paul demande aux corinthiens de déposer leurs collectes le premier jour de la semaine ? 1 corinthiens16 :1-2.', 9),
(167, 22, 'Selon Esaïe 58 :13 quel est le jour du Seigneur auquel jean fait référence en Apocalypse 1 :10 ?', 10),
(168, 23, '1.	Qu’est- ce qu’ils avaient sur leurs front les gens qui n’avaient pas été tués à Jérusalem ? Ezéchiel 9 :4-6', 1),
(169, 23, '2.	Qu’est-ce que les Israelites avaient fait pour échapper à la colère de Dieu en Egypte ? Exode 12 :7,13', 2),
(170, 23, '3.	Quels sont les trois éléments du sceau en rapport avec ce texte ? Exode 20 :11', 3),
(171, 23, '4. Quel est le signe entre Dieu et les enfants d\'Israël qui devra durer à perpétuité ? Exode 31 :16-17', 4),
(172, 23, '5.	Qu’est-ce qui distinguent les enfants de Dieu de ceux qui ne le sont pas ? Ezéchiel 20 :20.', 5),
(173, 23, '6.	Quel est le signe auquel on connaîtra que l’Éternel nous sanctifie ? Exode 31 :13.', 6),
(174, 23, '7.	Quels sont ceux qui échapperont à la colère de Jésus en son avènement ? Apocalypse 7 :1-3', 7),
(175, 23, '8. Que représente la femme assise sur une bête selon d’apocalypse 17 :3 ?', 8),
(176, 23, '9.	Qu’est-ce que la Bible interdit de faire d’après Apocalypse 14 :9-10 ?', 9),
(177, 23, '10. Quel est l’appelle de Dieu par rapport à ces églises de Babylone ? Apocalypse 18 :4.', 10);
INSERT INTO `traductions` (`id`, `type_contenu`, `contenu_id`, `cle_texte`, `texte_original`, `langue`, `texte_traduit`, `date_creation`, `date_modification`) VALUES
(1, 'interface', NULL, NULL, 'Qu\'est-ce que la Bible?', 'es', '¿Qué es la Biblia?', '2025-10-22 17:01:14', NULL),
(2, 'interface', NULL, NULL, 'La Bible est la Parole de Dieu, inspirée par le Saint-Esprit. Elle contient 66 livres écrits sur une période de 1500 ans par environ 40 auteurs différents. Malgré cette diversité, elle présente un message cohérent: le plan de Dieu pour sauver l\'humanité.', 'es', 'La Biblia es la Palabra de Dios, inspirada por el Espíritu Santo. Contiene 66 libros escritos durante un período de 1500 años por alrededor de 40 autores diferentes. A pesar de esta diversidad, presenta un mensaje coherente: el plan de Dios para salvar a la humanidad.', '2025-10-22 17:01:16', NULL),
(3, 'lecon', 1, 'titre', 'Qu\'est-ce que la Bible?', 'es', '¿Qué es la Biblia?', '2025-10-22 17:01:16', NULL),
(4, 'lecon', 1, 'contenu', 'La Bible est la Parole de Dieu, inspirée par le Saint-Esprit. Elle contient 66 livres écrits sur une période de 1500 ans par environ 40 auteurs différents. Malgré cette diversité, elle présente un message cohérent: le plan de Dieu pour sauver l\'humanité.', 'es', 'La Biblia es la Palabra de Dios, inspirada por el Espíritu Santo. Contiene 66 libros escritos durante un período de 1500 años por alrededor de 40 autores diferentes. A pesar de esta diversidad, presenta un mensaje coherente: el plan de Dios para salvar a la humanidad.', '2025-10-22 17:01:17', NULL),
(5, 'interface', NULL, NULL, '¿Qué es la Biblia?', 'es', '¿Qué es la Biblia?', '2025-10-22 17:01:21', NULL),
(6, 'interface', NULL, NULL, 'La Biblia es la Palabra de Dios, inspirada por el Espíritu Santo. Contiene 66 libros escritos durante un período de 1500 años por alrededor de 40 autores diferentes. A pesar de esta diversidad, presenta un mensaje coherente: el plan de Dios para salvar a la humanidad.', 'es', 'La Biblia es la Palabra de Dios, inspirada por el Espíritu Santo. Contiene 66 libros escritos durante un período de 1500 años por 40 autores diferentes. Al sopesar esta diversidad, presentó un mensaje coherente: el plan de Dios para salvar a la humanidad.', '2025-10-22 17:01:24', NULL),
(7, 'interface', NULL, NULL, 'Qu\'est-ce que la Bible?', 'kg', 'Biblia kele nki?', '2025-10-22 17:02:00', NULL),
(8, 'interface', NULL, NULL, 'La Bible est la Parole de Dieu, inspirée par le Saint-Esprit. Elle contient 66 livres écrits sur une période de 1500 ans par environ 40 auteurs différents. Malgré cette diversité, elle présente un message cohérent: le plan de Dieu pour sauver l\'humanité.', 'kg', 'Biblia kele Ndinga ya Nzambi, ya kupemama na Mpeve Santu. Yo kele ti mikanda 66 yina bo sonikaka na nsungi ya bamvula 1500 na bansoniki kiteso ya 40 ya kuswaswana. Ata yo kele ya kuswaswana, yo ke pesa nsangu ya ke landanaka: Lukanu ya Nzambi ya kugulusa bantu.', '2025-10-22 17:02:03', NULL),
(9, 'lecon', 1, 'titre', 'Qu\'est-ce que la Bible?', 'kg', 'Biblia kele nki?', '2025-10-22 17:02:03', NULL),
(10, 'lecon', 1, 'contenu', 'La Bible est la Parole de Dieu, inspirée par le Saint-Esprit. Elle contient 66 livres écrits sur une période de 1500 ans par environ 40 auteurs différents. Malgré cette diversité, elle présente un message cohérent: le plan de Dieu pour sauver l\'humanité.', 'kg', 'Biblia kele Ndinga ya Nzambi, ya kupemama na Mpeve Santu. Yo kele ti mikanda 66 yina bo sonikaka na nsungi ya bamvula 1500 na bansoniki kiteso ya 40 ya kuswaswana. Ata yo kele ya kuswaswana, yo ke pesa nsangu ya ke landanaka: Lukanu ya Nzambi ya kugulusa bantu.', '2025-10-22 17:02:03', NULL),
(11, 'interface', NULL, NULL, 'Biblia kele nki?', 'kg', 'Biblia kele nki?', '2025-10-22 17:02:06', NULL),
(12, 'interface', NULL, NULL, 'Biblia kele Ndinga ya Nzambi, ya kupemama na Mpeve Santu. Yo kele ti mikanda 66 yina bo sonikaka na nsungi ya bamvula 1500 na bansoniki kiteso ya 40 ya kuswaswana. Ata yo kele ya kuswaswana, yo ke pesa nsangu ya ke landanaka: Lukanu ya Nzambi ya kugulusa bantu.', 'kg', 'Biblia kele Ndinga ya Nzambi, ya kupemama na Mpeve Santu. Yoke kele ti mikanda 66 yina bo sonikaka na nsunging ya bamvula 1500 na bansoni cerf ya kuswana. Ata kele ya kuswanana, yoke pesa nsangu ya ke danaka: Lukanu ya kugusa kugusa.', '2025-10-22 17:02:09', NULL),
(13, 'interface', NULL, NULL, 'Combien de livres la Bible contient-elle?', 'kg', 'Mikanda ikwa kele na Biblia?', '2025-10-22 17:08:15', NULL),
(14, 'interface', NULL, NULL, 'Qui a inspiré les auteurs de la Bible?', 'kg', 'Nani pesaka bansoniki ya Biblia mpeve?', '2025-10-22 17:08:18', NULL),
(15, 'interface', NULL, NULL, 'Quel est le message principal de la Bible?', 'kg', 'Inki kele nsangu ya mfunu ya Biblia?', '2025-10-22 17:08:21', NULL),
