(28, 'interface', NULL, NULL, 'Biblia kele nki?', 'en', 'Biblia kele nki?', '2025-10-22 17:09:24', NULL),
(29, 'interface', NULL, NULL, 'Biblia kele Ndinga ya Nzambi, ya kupemama na Mpeve Santu. Yoke kele ti mikanda 66 yina bo sonikaka na nsunging ya bamvula 1500 na bansoni cerf ya kuswana. Ata kele ya kuswanana, yoke pesa nsangu ya ke danaka: Lukanu ya kugusa kugusa.', 'en', 'Biblia kele Ndinga ya Nzambi, ya kupemama na Mpeve Santu. Yoke kele ti mikanda 66 yina bo sonikaka na nsunging ya bamvula 1500 na bansoni deer ya kuswana. Ata kele ya kuswanana, yoke pesa nsangu ya ke danaka: Lukanu ya kugusa kugusa.', '2025-10-22 17:09:26', NULL),
(30, 'interface', NULL, NULL, 'Biblia kele Ndinga ya Nzambi, ya kupemama na Mpeve Santu. Yoke kele ti mikanda 66 yina bo sonikaka na nsunging ya bamvula 1500 na bansoni deer ya kuswana. Ata kele ya kuswanana, yoke pesa nsangu ya ke danaka: Lukanu ya kugusa kugusa.', 'en', 'Biblia kele Ndinga ya Nzambi, ya kupemama na Mpeve Santu. Yoke kele ti mikanda 66 yina bo sonikaka na nsunging ya bamvula 1500 na bansoni deer ya kuswana. Ata kele ya kuswanana, yoke pesa nsangu ya ke danaka: Lukanu ya kugusa kugusa.', '2025-10-22 17:09:39', NULL),
(31, 'interface', NULL, NULL, 'Qu\'est-ce que la Bible?', 'sw', 'Biblia ni nini?', '2025-10-22 17:10:09', NULL),
(32, 'interface', NULL, NULL, 'La Bible est la Parole de Dieu, inspirée par le Saint-Esprit. Elle contient 66 livres écrits sur une période de 1500 ans par environ 40 auteurs différents. Malgré cette diversité, elle présente un message cohérent: le plan de Dieu pour sauver l\'humanité.', 'sw', 'Bibilia ni Neno la Mungu, lililoongozwa na Roho Mtakatifu. Inayo vitabu 66 vilivyoandikwa kwa kipindi cha miaka 1500 na waandishi karibu 40 tofauti. Pamoja na utofauti huu, inawasilisha ujumbe thabiti: mpango wa Mungu wa kuokoa ubinadamu.', '2025-10-22 17:10:12', NULL),
(33, 'lecon', 1, 'titre', 'Qu\'est-ce que la Bible?', 'sw', 'Biblia ni nini?', '2025-10-22 17:10:12', NULL),
(34, 'lecon', 1, 'contenu', 'La Bible est la Parole de Dieu, inspirée par le Saint-Esprit. Elle contient 66 livres écrits sur une période de 1500 ans par environ 40 auteurs différents. Malgré cette diversité, elle présente un message cohérent: le plan de Dieu pour sauver l\'humanité.', 'sw', 'Bibilia ni Neno la Mungu, lililoongozwa na Roho Mtakatifu. Inayo vitabu 66 vilivyoandikwa kwa kipindi cha miaka 1500 na waandishi karibu 40 tofauti. Pamoja na utofauti huu, inawasilisha ujumbe thabiti: mpango wa Mungu wa kuokoa ubinadamu.', '2025-10-22 17:10:12', NULL),
(35, 'interface', NULL, NULL, 'Combien de livres la Bible contient-elle?', 'sw', 'Je! Ni vitabu vingapi katika Bibilia?', '2025-10-22 17:10:15', NULL),
(36, 'interface', NULL, NULL, 'Qui a inspiré les auteurs de la Bible?', 'sw', 'Ni nani aliyewahimiza waandishi wa Bibilia?', '2025-10-22 17:10:17', NULL),
(37, 'interface', NULL, NULL, 'Quel est le message principal de la Bible?', 'sw', 'Je! Ni ujumbe gani kuu wa Bibilia?', '2025-10-22 17:10:20', NULL),
