INSERT INTO `versets` (`id`, `reference`, `livre`, `chapitre`, `verset`, `texte`, `version`) VALUES
(1, 'Jean 3:16', 'Jean', 3, 16, 'Car Dieu a tant aimé le monde qu\'il a donné son Fils unique, afin que quiconque croit en lui ne périsse point, mais qu\'il ait la vie éternelle.', 'LSG'),
(2, 'Romains 3:23', 'Romains', 3, 23, 'Car tous ont péché et sont privés de la gloire de Dieu.', 'LSG'),
(3, 'Romains 6:23', 'Romains', 6, 23, 'Car le salaire du péché, c\'est la mort; mais le don gratuit de Dieu, c\'est la vie éternelle en Jésus-Christ notre Seigneur.', 'LSG'),
(4, 'Éphésiens 2:8', 'Éphésiens', 2, 8, 'Car c\'est par la grâce que vous êtes sauvés, par le moyen de la foi. Et cela ne vient pas de vous, c\'est le don de Dieu.', 'LSG'),
(5, '1 Jean 1:9', '1 Jean', 1, 9, 'Si nous confessons nos péchés, il est fidèle et juste pour nous les pardonner, et pour nous purifier de toute iniquité.', 'LSG'),
(6, 'Matthieu 11:28', 'Matthieu', 11, 28, 'Venez à moi, vous tous qui êtes fatigués et chargés, et je vous donnerai du repos.', 'LSG'),
(7, 'Psaumes 23:1', 'Psaumes', 23, 1, 'L\'Éternel est mon berger: je ne manquerai de rien.', 'LSG'),
(8, 'Philippiens 4:13', 'Philippiens', 4, 13, 'Je puis tout par celui qui me fortifie.', 'LSG');
